type LoginHotelContext = {
  id: string;
  slug: string;
  accountNumber?: number | null;
  displayName: string;
  city?: string | null;
  country?: string | null;
  requestedKey?: string;
};

function hotelSignForLogin(hotel: LoginHotelContext): string {
  return [hotel.city, hotel.country].filter(Boolean).join(", ") || "Hotel operations";
}

function hotelAccountKeyForLogin(hotel: LoginHotelContext): string {
  return hotel.accountNumber ? String(hotel.accountNumber) : hotel.slug;
}

async function resolveLoginHotel(req: Request): Promise<LoginHotelContext> {
  const queryHotel = typeof req.query.hotel === "string" ? req.query.hotel.trim() : "";
  const bodyHotelSlug = typeof req.body?.hotelSlug === "string" ? req.body.hotelSlug.trim() : "";
  const bodyHotel = typeof req.body?.hotel === "string" ? req.body.hotel.trim() : "";
  const bodyLoginId = typeof req.body?.loginId === "string" ? req.body.loginId.trim() : "";
  const bodyLoginHotelKey = /^\d+$/.test(bodyLoginId) || bodyLoginId.includes("-") ? bodyLoginId : "";
  const raw = queryHotel || bodyHotelSlug || bodyHotel || bodyLoginHotelKey;
  if (!raw) {
    return {
      id: "",
      slug: "",
      displayName: "ChatStay Hotel Portal",
      city: "Enter your hotel account number",
      country: null
    };
  }
  const numericAccount = /^\d+$/.test(raw) ? Number(raw) : null;
  const hotelIdByAccount = numericAccount
    ? await prisma.$queryRaw<Array<{ id: string }>>(Prisma.sql`SELECT id FROM "Hotel" WHERE "accountNumber" = ${numericAccount} LIMIT 1`)
    : [];
  const hotel = numericAccount
    ? await prisma.hotel
        .findUnique({
          where: { id: hotelIdByAccount[0]?.id ?? "" },
          select: { id: true, slug: true, displayName: true, city: true, country: true }
        })
        .then((h) => (h ? { ...h, accountNumber: numericAccount } : null))
    : await prisma.hotel.findUnique({
        where: { slug: raw },
        select: { id: true, slug: true, displayName: true, city: true, country: true }
      });
  if (!hotel) {
    return {
      id: "",
      slug: raw,
      requestedKey: raw,
      displayName: "ChatStay Hotel Portal",
      city: "Hotel account not found",
      country: null
    };
  }
  return hotel;
}

function loginPageHtml(hotel?: LoginHotelContext): string {
  const hotelAccountKey = hotel?.id ? hotelAccountKeyForLogin(hotel) : "";
  const hotelDisplayName = hotel?.displayName ?? "ChatStay Hotel Portal";
  const isKnownHotel = Boolean(hotel?.id);
  const hotelContextField = isKnownHotel ? `<input type="hidden" name="hotelSlug" value="${escapeHtml(hotelAccountKey)}" />` : "";
  const loginAlerts =
    hotel?.requestedKey && !hotel.id
      ? `<p class="badge alert">No hotel account found for <code>${escapeHtml(hotel.requestedKey)}</code>. Use the numeric account number from the Owner Console.</p>`
      : "";
  return readView("login.html")
    .replace("{{HOTEL_DISPLAY_LINE}}", `${escapeHtml(hotelDisplayName)} — sign in to manage reservations, rooms, and guest messaging.`)
    .replaceAll("{{HOTEL_ACCOUNT_KEY}}", escapeHtml(hotelAccountKey))
    .replaceAll("{{HOTEL_HIDDEN_FIELD}}", hotelContextField)
    .replace("{{LOGIN_ALERTS}}", loginAlerts)
    .replaceAll('href="/admin/forgot-password"', `href="/admin/forgot-password?hotel=${encodeURIComponent(hotelAccountKey)}"`)
    .replace("{{LOGIN_DEMO_SECTION}}", loginDemoSectionHtml());
}

/** Client-side polling for conversation activity (no WebSockets in this stack). */
function getAdminLiveScript(): string {
  return `<script>
(function () {
  var POLL_MS = 2500;
  var disabled = false;
  var lastSince = new Date(Date.now() - 15000).toISOString();
  var pendingBadge = 0;
  var listReloadTimer = null;
  var audioCtx = null;
  var detailRefreshInFlight = false;
  var renderedMessageIds = new Set();

  function esc(s) {
    return String(s || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/"/g, "&quot;");
  }
  function formatDt(iso) {
    try {
      return new Date(iso).toISOString().replace("T", " ").slice(0, 16);
    } catch (e) {
      return "";
    }
  }
  function toast(title, body, kind) {
    var stack = document.getElementById("adminToastStack");
    if (!stack) return;
    var el = document.createElement("div");
    el.className = "admin-toast" + (kind === "booking" ? " admin-toast-booking" : "");
    el.innerHTML = '<strong class="admin-toast-title">' + esc(title) + '</strong><p class="admin-toast-body">' + esc(body) + '</p>';
    stack.appendChild(el);
    window.setTimeout(function () {
      el.classList.add("admin-toast-out");
      window.setTimeout(function () { el.remove(); }, 400);
    }, 9000);
  }
  function ensureAudioUnlocked() {
    if (audioCtx) return audioCtx;
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      if (audioCtx.state === "suspended" && audioCtx.resume) audioCtx.resume().catch(function () {});
    } catch (e) {}
    return audioCtx;
  }
  function beepLiveAlert() {
    if (localStorage.getItem("notifSoundMuted") === "true") return;
    try {
      var ctx = ensureAudioUnlocked();
      if (!ctx) return;
      var o = ctx.createOscillator();
      var g = ctx.createGain();
      o.type = "triangle";
      o.frequency.setValueAtTime(740, ctx.currentTime);
      o.frequency.setValueAtTime(980, ctx.currentTime + 0.12);
      g.gain.setValueAtTime(0.0001, ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.06, ctx.currentTime + 0.02);
      g.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 0.34);
      o.connect(g);
      g.connect(ctx.destination);
      o.start();
      o.stop(ctx.currentTime + 0.36);
    } catch (e) {}
  }
  function updateBadge(delta) {
    var badge = document.getElementById("adminConvLiveBadge");
    if (!badge) return;
    pendingBadge = Math.max(0, pendingBadge + delta);
    badge.textContent = String(Math.min(99, pendingBadge));
    badge.hidden = pendingBadge === 0;
  }
  function currentConversationId() {
    var n = document.querySelector("[data-chat-conversation-id]");
    return n ? n.getAttribute("data-chat-conversation-id") : null;
  }
  function rememberRenderedMessages() {
    document.querySelectorAll("[data-chat-message-id]").forEach(function (el) {
      var id = el.getAttribute("data-chat-message-id");
      if (id) renderedMessageIds.add(id);
    });
  }
  // Mirror of server-side aiIntentDisplayLabel: hospitality-readable wording for staff, internal
  // flow plumbing hidden. Keep this list in sync with src/core/operationalLabels.ts.
  var INTENT_HIDDEN = {
    MANUAL_REPLY: 1, GUEST_JOURNEY_REPLY: 1, PRE_ARRIVAL_GUEST_REPLY: 1, BOOKING_CHANGE_MENU: 1,
    AGENT_HANDOFF: 1, IN_STAY_SERVICE_MENU: 1, IN_STAY_WELCOME_MENU: 1, IN_STAY_VIEW_STAY: 1,
    IN_STAY_EXTRA_REQUEST_LOGGED: 1, IN_STAY_COMPLAINT_RECEIVED: 1, CHECK_IN_BILL_SUMMARY: 1
  };
  var INTENT_FRIENDLY = {
    PRE_ARRIVAL_24H: "Pre-arrival reminder",
    CHECKIN_DAY: "Arrival day message",
    POST_CHECKOUT_THANK_YOU: "Post-stay thank-you",
    REVIEW_REQUEST: "Review request",
    REPEAT_GUEST_PROMO: "Repeat-guest offer",
    GUEST_COMPLAINT: "Complaint",
    GUEST_DISSATISFACTION: "Guest dissatisfaction",
    GUEST_ESCALATION: "Escalation",
    GUEST_PAYMENT_ISSUE: "Payment issue",
    GUEST_REFUND_REQUEST: "Refund request",
    GUEST_CANCELLATION_REQUEST: "Cancellation request",
    GUEST_BOOKING_MODIFICATION: "Booking modification",
    GUEST_SPECIAL_REQUEST: "Special request",
    GUEST_LATE_CHECKOUT_REQUEST: "Late check-out request",
    GUEST_EARLY_CHECKIN_REQUEST: "Early check-in request",
    GUEST_LATE_ARRIVAL: "Late arrival",
    GUEST_ARRIVAL_SUPPORT_REQUEST: "Arrival support",
    GUEST_ARRIVAL_TIME_UPDATE: "Arrival time update",
    GUEST_ON_THE_WAY: "On the way"
  };
  function intentLabel(v) {
    if (!v) return "";
    if (INTENT_HIDDEN[v]) return "";
    if (INTENT_FRIENDLY[v]) return INTENT_FRIENDLY[v];
    var s = String(v).replace(/^(GUEST_|PRE_|POST_)/, "").replace(/_/g, " ").toLowerCase();
    return s.charAt(0).toUpperCase() + s.slice(1);
  }
  function buildBubble(m) {
    var inbound = m.direction === "INBOUND";
    var sender = inbound ? "Guest" : (m.aiIntent === "MANUAL_REPLY" ? "Staff" : "AI");
    var label = intentLabel(m.aiIntent);
    var intentHtml = label ? '<p class="bubble-meta">' + esc(label) + "</p>" : "";
    return (
      '<article class="bubble ' + (inbound ? "inbound" : "outbound") + '" data-chat-message-id="' + esc(m.id) + '">' +
      '<div class="bubble-head"><span><strong>' + esc(sender) + '</strong></span><span>' + formatDt(m.createdAt) + "</span></div>" +
      '<p class="bubble-body">' + esc(m.body) + "</p>" + intentHtml + "</article>"
    );
  }
  function refreshDetailMessages(cid) {
    if (detailRefreshInFlight) return;
    var wrap = document.querySelector("[data-chat-conversation-id]");
    if (!wrap || wrap.getAttribute("data-chat-conversation-id") !== cid) return;
    rememberRenderedMessages();
    var since = wrap.getAttribute("data-chat-last-msg-at") || "";
    var url = "/admin/conversations/live/" + encodeURIComponent(cid) + "/messages?since=" + encodeURIComponent(since);
    detailRefreshInFlight = true;
    fetch(url, { credentials: "same-origin", headers: { Accept: "application/json" } })
      .then(function (r) {
        if (r.status === 401 || r.status === 403) return null;
        return r.json();
      })
      .then(function (data) {
        if (!data || !data.ok || !data.messages || !data.messages.length) return;
        var timeline = document.querySelector(".chat-messages .timeline");
        if (!timeline) return;
        data.messages.forEach(function (m) {
          if (m.id && renderedMessageIds.has(m.id)) return;
          timeline.insertAdjacentHTML("beforeend", buildBubble(m));
          if (m.id) renderedMessageIds.add(m.id);
        });
        var last = data.messages[data.messages.length - 1];
        if (last && last.createdAt) wrap.setAttribute("data-chat-last-msg-at", last.createdAt);
        var cm = document.querySelector(".chat-messages");
        if (cm) cm.scrollTop = cm.scrollHeight;
      })
      .catch(function () {})
      .finally(function () { detailRefreshInFlight = false; });
  }
  function maybeReloadList() {
    var p = (window.location.pathname || "").replace(/\\/+$/, "") || "/";
    if (p !== "/admin/conversations") return;
    if (listReloadTimer) window.clearTimeout(listReloadTimer);
    listReloadTimer = window.setTimeout(function () {
      window.location.reload();
    }, 500);
  }
  function handleEvents(events) {
    if (!events || !events.length) return;
    updateBadge(events.length);
    beepLiveAlert();
    events.forEach(function (ev) {
      var t = ev.title || "Conversation";
      var b = ev.preview || "";
      toast(t, b, ev.category === "booking" ? "booking" : "inquiry");
      if (ev.conversationId && ev.conversationId === currentConversationId()) {
        refreshDetailMessages(ev.conversationId);
      }
    });
    maybeReloadList();
  }
  function pollActivity() {
    if (disabled) return;
    fetch("/admin/conversations/live/activity?since=" + encodeURIComponent(lastSince), {
      credentials: "same-origin",
      headers: { Accept: "application/json" }
    })
      .then(function (r) {
        if (r.status === 401 || r.status === 403) {
          disabled = true;
          return null;
        }
        return r.json();
      })
      .then(function (data) {
        if (!data || !data.ok) return;
        if (data.serverTime) lastSince = data.serverTime;
        handleEvents(data.events || []);
      })
      .catch(function () {});
  }
  function pollDetailCatchUp() {
    var cid = currentConversationId();
    if (!cid) return;
    refreshDetailMessages(cid);
  }
  var link = document.querySelector("[data-admin-conv-link]");
  if (link) {
    link.addEventListener("click", function () {
      pendingBadge = 0;
      var badge = document.getElementById("adminConvLiveBadge");
      if (badge) badge.hidden = true;
    });
  }
  ["pointerdown", "keydown", "touchstart", "click"].forEach(function (ev) {
    window.addEventListener(ev, ensureAudioUnlocked, { once: true, passive: true });
  });
  window.setInterval(function () {
    pollActivity();
    pollDetailCatchUp();
  }, POLL_MS);
  pollActivity();
  pollDetailCatchUp();
})();
</script>`;
}

function getAdminNotificationScript(): string {
  return `<script>
(function () {
  var POLL_MS = 3000;
  var notifBtn = document.getElementById("adminNotifBell");
  var notifBadge = document.getElementById("adminNotifBadge");
  var notifList = document.getElementById("adminNotifList");
  var notifEmpty = document.getElementById("adminNotifEmpty");
  var notifReadAll = document.getElementById("adminNotifReadAll");
  var muteBtn = document.getElementById("adminNotifMute");
  var panel = document.getElementById("adminNotifPanel");
  var attentionStrip = document.getElementById("adminAttentionStrip");
  var attentionList = document.getElementById("adminAttentionList");
  if (!notifBtn || !notifBadge || !notifList || !notifEmpty || !notifReadAll || !muteBtn || !panel) return;

  panel.hidden = true;
  panel.setAttribute("hidden", "");

  var knownIds = new Set();
  var notifBootstrapped = false;
  var soundMuted = localStorage.getItem("notifSoundMuted") === "true";
  var audioCtx = null;
  var iconOn = "🔔";
  var iconOff = "🔕";
  muteBtn.textContent = soundMuted ? iconOff : iconOn;
  muteBtn.title = soundMuted ? "Enable alert sound" : "Mute alert sound";

  function esc(s) {
    return String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/"/g, "&quot;");
  }
  function sevClass(sev) {
    if (sev === "critical") return "critical";
    if (sev === "high") return "high";
    if (sev === "normal") return "normal";
    return "info";
  }
  function isHousekeepingAttention(item) {
    if (!item) return false;
    if (item.category === "housekeeping") return true;
    var st = String(item.sourceType || "");
    return st.indexOf("HK_") === 0 || st === "ROOM_BOARD_MAINTENANCE";
  }
  function shouldBeep(sev, item) {
    if (sev === "critical" || sev === "high") return true;
    if (isHousekeepingAttention(item)) return true;
    return false;
  }
  function ensureAudioUnlocked() {
    if (audioCtx) return audioCtx;
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      if (audioCtx.state === "suspended" && audioCtx.resume) audioCtx.resume().catch(function () {});
    } catch (e) {}
    return audioCtx;
  }
  function playTone(ctx, freqHz, startOffset, durationSec, peak) {
    var o = ctx.createOscillator();
    var g = ctx.createGain();
    o.type = "sine";
    o.frequency.setValueAtTime(freqHz, ctx.currentTime + startOffset);
    var pk = peak == null ? 0.04 : peak;
    g.gain.setValueAtTime(0.0001, ctx.currentTime + startOffset);
    g.gain.exponentialRampToValueAtTime(pk, ctx.currentTime + startOffset + 0.012);
    g.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + startOffset + durationSec);
    o.connect(g);
    g.connect(ctx.destination);
    o.start(ctx.currentTime + startOffset);
    o.stop(ctx.currentTime + startOffset + durationSec + 0.02);
  }
  function pulseBell() {
    if (!notifBtn) return;
    notifBtn.classList.remove("admin-notif-bell-pulse");
    void notifBtn.offsetWidth;
    notifBtn.classList.add("admin-notif-bell-pulse");
    window.setTimeout(function () {
      notifBtn.classList.remove("admin-notif-bell-pulse");
    }, 4500);
  }
  function beep(style) {
    if (soundMuted) return;
    try {
      var ctx = ensureAudioUnlocked();
      if (!ctx) return;
      if (style === "hk") {
        playTone(ctx, 660, 0, 0.11, 0.045);
        playTone(ctx, 880, 0.13, 0.12, 0.05);
      } else {
        playTone(ctx, 880, 0, 0.16, 0.04);
      }
      pulseBell();
    } catch (e) {}
  }
  function updateBadge(n) {
    var count = Number(n || 0);
    notifBadge.textContent = String(Math.min(99, count));
    notifBadge.hidden = count <= 0;
  }
  function categoryLabel(cat) {
    switch (cat) {
      case "bookings": return { label: "Bookings", tone: "#0f766e" };
      case "messages": return { label: "WhatsApp", tone: "#0a7f3f" };
      case "housekeeping": return { label: "Housekeeping", tone: "#0369a1" };
      case "maintenance": return { label: "Maintenance", tone: "#9a3412" };
      case "rooms": return { label: "Front Desk", tone: "#5b21b6" };
      case "payments": return { label: "Payments", tone: "#92400e" };
      case "restaurant": return { label: "Restaurant", tone: "#7c2d12" };
      case "activities": return { label: "Activities", tone: "#0f766e" };
      case "support": return { label: "Complaints", tone: "#9f1239" };
      default: return { label: cat || "System", tone: "#475569" };
    }
  }
  function relTime(when) {
    if (!when) return "";
    var t = typeof when === "string" ? Date.parse(when) : (when instanceof Date ? when.getTime() : Number(when));
    if (!t || isNaN(t)) return "";
    var diff = Date.now() - t;
    if (diff < 60000) return "just now";
    var m = Math.round(diff / 60000);
    if (m < 60) return m + "m ago";
    var h = Math.round(m / 60);
    if (h < 24) return h + "h ago";
    var d = Math.round(h / 24);
    return d + "d ago";
  }
  function renderList(items) {
    notifList.innerHTML = "";
    if (!items || !items.length) {
      notifEmpty.hidden = false;
      return;
    }
    notifEmpty.hidden = true;
    items.forEach(function (item) {
      var li = document.createElement("li");
      li.className = "admin-notif-item sev-" + sevClass(item.severity);
      var cat = categoryLabel(item.category || "system");
      var pill =
        '<span class="admin-notif-cat" style="background:' + cat.tone + '1a;color:' + cat.tone +
        ';border:1px solid ' + cat.tone + '40">' + esc(cat.label) + '</span>';
      var when = relTime(item.createdAt);
      li.innerHTML =
        '<a href="' + esc(item.link || "#") + '" data-notif-id="' + esc(item.id) + '">' +
        '<div class="admin-notif-meta">' + pill +
        (when ? '<span class="admin-notif-time">' + esc(when) + '</span>' : "") + "</div>" +
        '<div class="admin-notif-title">' + esc(item.title || item.type || "Notification") + "</div>" +
        '<div class="admin-notif-body">' + esc(item.body || "") + "</div>" +
        "</a>";
      notifList.appendChild(li);
    });
  }
  function renderAttention(items) {
    if (!attentionStrip || !attentionList) return;
    var urgent = (items || []).filter(function (x) { return x && x.readAt == null && (x.severity === "critical" || x.severity === "high"); }).slice(0, 5);
    if (!urgent.length) {
      attentionStrip.hidden = true;
      attentionList.innerHTML = "";
      return;
    }
    attentionStrip.hidden = false;
    attentionList.innerHTML = urgent
      .map(function (n) {
        var href = n.link || "#";
        return '<li><a href="' + esc(href) + '" style="color:#7f1d1d;text-decoration:none"><strong>' + esc(n.title || "Alert") + ":</strong> " + esc(n.body || "") + "</a></li>";
      })
      .join("");
  }
  // Some sessions (platform-superadmin pseudo-account, or staff without a HotelUser row) cannot read the
  // hotel notification feed. The server returns 401 on every endpoint. Without this guard the bell would
  // appear functional but every action — including "Read all" — would silently swallow a 401, which looks
  // broken to the operator. When we detect a 401, hide the entire notification surface and stop polling.
  var notifDisabled = false;
  var pollHandle = null;
  function disableNotifications() {
    if (notifDisabled) return;
    notifDisabled = true;
    if (pollHandle != null) {
      window.clearInterval(pollHandle);
      pollHandle = null;
    }
    panel.hidden = true;
    panel.setAttribute("hidden", "");
    var wrap = notifBtn.closest(".admin-notif-wrap");
    if (wrap) {
      wrap.style.display = "none";
    } else {
      notifBtn.style.display = "none";
      notifBadge.style.display = "none";
    }
    notifBtn.classList.remove("admin-notif-bell-pulse");
  }
  async function fetchUnreadCount() {
    if (notifDisabled) return;
    var r = await fetch("/auth/notifications/unread-count", { credentials: "same-origin", headers: { Accept: "application/json" } });
    if (r.status === 401) { disableNotifications(); return; }
    if (!r.ok) return;
    var j = await r.json();
    updateBadge(j.unreadCount || 0);
  }
  async function fetchLatest() {
    if (notifDisabled) return;
    var r = await fetch("/auth/notifications?limit=10", { credentials: "same-origin", headers: { Accept: "application/json" } });
    if (r.status === 401) { disableNotifications(); return; }
    if (!r.ok) return;
    var j = await r.json();
    var items = Array.isArray(j.notifications) ? j.notifications : [];
    var skipBeeps = !notifBootstrapped;
    notifBootstrapped = true;
    for (var i = 0; i < items.length; i++) {
      var n = items[i];
      if (!knownIds.has(n.id)) {
        knownIds.add(n.id);
        if (!skipBeeps && n.readAt == null && shouldBeep(n.severity, n)) {
          beep(isHousekeepingAttention(n) ? "hk" : "default");
        }
      }
    }
    renderList(items);
    renderAttention(items);
  }
  // Original DOM home of the panel (so we can return it on close).
  var panelHome = panel.parentNode;
  var panelHomeNext = panel.nextSibling;
  function portalPanelOpen() {
    // Move the panel onto <body> so no ancestor (sticky sidebar with overflow,
    // backdrop-filter cards, transforms on hover, etc.) can create a stacking
    // context that lets page content render on top of it.
    if (panel.parentNode !== document.body) {
      document.body.appendChild(panel);
    }
    panel.classList.add("admin-notif-panel-floating");
  }
  function portalPanelClose() {
    panel.classList.remove("admin-notif-panel-floating");
    if (panel.parentNode !== panelHome && panelHome) {
      if (panelHomeNext && panelHomeNext.parentNode === panelHome) {
        panelHome.insertBefore(panel, panelHomeNext);
      } else {
        panelHome.appendChild(panel);
      }
    }
    panel.style.top = "";
    panel.style.left = "";
    panel.style.right = "";
    panel.style.width = "";
  }
  function positionNotifPanel() {
    // When the bell lives inside the sticky sidebar (which has overflow:auto), an
    // absolutely-positioned dropdown gets clipped or rendered behind the main
    // content. We anchor the panel with position:fixed + computed coordinates so
    // it always escapes the sidebar bounds while still pointing at the bell.
    if (!notifBtn.closest(".sidebar-top-controls")) return;
    var rect = notifBtn.getBoundingClientRect();
    var panelWidth = Math.min(360, window.innerWidth - 24);
    var maxLeft = Math.max(12, window.innerWidth - panelWidth - 12);
    var preferredLeft = Math.round(rect.left);
    panel.style.position = "fixed";
    panel.style.top = Math.round(rect.bottom + 8) + "px";
    panel.style.left = Math.round(Math.max(12, Math.min(preferredLeft, maxLeft))) + "px";
    panel.style.width = panelWidth + "px";
    panel.style.right = "auto";
  }
  notifBtn.addEventListener("click", function () {
    var willOpen = panel.hidden;
    if (willOpen) {
      portalPanelOpen();
      panel.hidden = false;
      positionNotifPanel();
    } else {
      panel.hidden = true;
      portalPanelClose();
    }
    notifBtn.classList.remove("admin-notif-bell-pulse");
  });
  window.addEventListener("resize", function () { if (!panel.hidden) positionNotifPanel(); });
  window.addEventListener("scroll", function () { if (!panel.hidden) positionNotifPanel(); }, { passive: true });
  document.addEventListener("click", function (e) {
    if (panel.hidden) return;
    var t = e.target;
    if (!panel.contains(t) && !notifBtn.contains(t)) {
      panel.hidden = true;
      portalPanelClose();
    }
  });
  notifList.addEventListener("click", async function (e) {
    var t = e.target;
    var a = t && t.closest ? t.closest("[data-notif-id]") : null;
    if (!a) return;
    var id = a.getAttribute("data-notif-id");
    if (!id) return;
    // If the user is following a link inside the panel (SPA navigation), tidy
    // up so the panel doesn't stay floating on <body> after navigation.
    if (a.tagName === "A" && a.getAttribute("href")) {
      panel.hidden = true;
      portalPanelClose();
    }
    var r = await fetch("/auth/notifications/" + encodeURIComponent(id) + "/read", { method: "POST", credentials: "same-origin", headers: { Accept: "application/json" } }).catch(function () { return null; });
    if (r && r.status === 401) { disableNotifications(); return; }
    fetchUnreadCount();
    fetchLatest();
  });
  document.addEventListener("keydown", function (e) {
    if (panel.hidden) return;
    if (e.key === "Escape" || e.key === "Esc") {
      panel.hidden = true;
      portalPanelClose();
    }
  });
  notifReadAll.addEventListener("click", async function () {
    var r = await fetch("/auth/notifications/read-all", { method: "POST", credentials: "same-origin", headers: { Accept: "application/json" } }).catch(function () { return null; });
    if (r && r.status === 401) { disableNotifications(); return; }
    fetchUnreadCount();
    fetchLatest();
  });
  muteBtn.addEventListener("click", function () {
    soundMuted = !soundMuted;
    localStorage.setItem("notifSoundMuted", soundMuted ? "true" : "false");
    muteBtn.textContent = soundMuted ? iconOff : iconOn;
    muteBtn.title = soundMuted ? "Enable alert sound" : "Mute alert sound";
    if (!soundMuted) ensureAudioUnlocked();
  });
  ["pointerdown", "keydown", "touchstart", "click"].forEach(function (ev) {
    window.addEventListener(ev, ensureAudioUnlocked, { once: true, passive: true });
  });

  function poll() {
    if (notifDisabled) return;
    fetchUnreadCount();
    fetchLatest();
  }
  poll();
  pollHandle = window.setInterval(poll, POLL_MS);
})();
</script>`;
}

function renderLayout(
  content: string,
  authenticated: boolean,
  opts: { hotelName?: string; hotelSign?: string; hotelSlug?: string; hotelKnown?: boolean } = {}
): string {
  const layout = readView("layout.html");
  const sess = authenticated ? auditActorContext.getStore()?.session : undefined;
  const permLike = (sess?.permissions ?? undefined) as PermissionMatrixLike | undefined;
  const resolvedHotelName = opts.hotelName ?? sess?.hotelName ?? hotelName;
  const resolvedHotelSlug = opts.hotelSlug ?? sess?.hotelSlug ?? defaultHotelSlug;
  const resolvedHotelSign = opts.hotelSign ?? hotelSign;
  // When the visitor is unauthenticated AND we don't have a real hotel resolved
  // (e.g. /admin/login?hotel=2 with a non-existent account number), suppress the
  // hotel-card. Otherwise the sidebar renders a misleading "ChatStay Hotel Portal /
  // Hotel account not found" badge that competes with the in-page error message.
  const showHotelCard = authenticated || opts.hotelKnown === true;
  const hotelCardHtml = showHotelCard
    ? `<div class="hotel-card"><strong>${escapeHtml(resolvedHotelName)}</strong><span>${escapeHtml(resolvedHotelSign)}</span></div>`
    : "";
  const uiErrorContextAttrs = sess
    ? ` data-ui-user-id="${escapeHtml(sess.staffId)}" data-ui-role="${escapeHtml(String(sess.role))}" data-ui-hotel-slug="${escapeHtml(resolvedHotelSlug)}"${
        sess.activePropertyId ? ` data-ui-property-id="${escapeHtml(String(sess.activePropertyId))}"` : ""
      }${sess.activeWorkspace ? ` data-ui-workspace="${escapeHtml(String(sess.activeWorkspace))}"` : ""}`
    : "";
  const perm = authenticated ? sess?.permissions : undefined;
  const role = authenticated ? sess?.role : undefined;
  const workspaces =
    sess && permLike ? listAccessibleWorkspaces(String(role), permLike) : ([] as PmsWorkspaceId[]);
  const activeWs: PmsWorkspaceId | undefined =
    sess && permLike
      ? sess.activeWorkspace && workspaces.includes(sess.activeWorkspace)
        ? sess.activeWorkspace
        : inferDefaultWorkspace(String(role), permLike)
      : undefined;
  const useFrontDeskChrome = activeWs === "front_desk";
  const useOwnerChrome = activeWs === "owner";
  const useRestaurantChrome = activeWs === "restaurant";
  const useHousekeepingManagerChrome = activeWs === "housekeeping" && role !== "HOUSEKEEPING";
  // Settings / property setup / staff & permissions / billing / integrations are
  // managerial scope. A FRONTDESK / RESTAURANT / HOUSEKEEPING staff session must
  // never expose those entry points in the sidebar — they get a personal "Profile"
  // link instead. Owners and managers (including users with explicit USERS:VIEW)
  // continue to see the full Settings group.
  const isManagerialRole = role === "OWNER" || role === "MANAGER";
  const canSeeAdminSettings = Boolean(
    isManagerialRole || (perm && hasPermission(perm, "USERS", "VIEW"))
  );
  const canNavHousekeeping =
    !perm ||
    hasPermission(perm, "HOUSEKEEPING", "VIEW") ||
    hasPermission(perm, "ROOMS", "EDIT");
  const canNavOutlet = !perm || hasPermission(perm, "OUTLET", "VIEW");
  const canNavFb = !perm || hasPermission(perm, "OUTLET", "VIEW");
  const canNavComms = !perm || hasPermission(perm, "CONVERSATIONS", "VIEW");
  const canNavBookings = !perm || hasPermission(perm, "BOOKINGS", "VIEW");
  const canNavRooms = !perm || hasPermission(perm, "ROOMS", "VIEW");
  const canNavReports = !perm || hasPermission(perm, "REPORTS", "VIEW");
  const canCreateBookings = Boolean(perm && hasPermission(perm, "BOOKINGS", "CREATE"));
  type AdminNavGroup =
    | "dashboard"
    | "reservations"
    | "frontdesk"
    | "inventory"
    | "housekeeping"
    | "comms"
    | "fb"
    | "insights"
    | "account"
    | "modules";
  type AdminNavItem = { group: AdminNavGroup; href: string; label: string; attrs?: string };
  type AdminSectionLink = { href: string; label: string; attrs?: string };
  type AdminSection = { group: AdminNavGroup; links: Array<AdminSectionLink | string> };
  const navLink = (item: AdminNavItem) =>
    `<a class="top-level-link" data-top-group="${item.group}" href="${item.href}"${item.attrs ? ` ${item.attrs}` : ""}>${item.label}</a>`;
  const sectionLink = (item: AdminSectionLink) =>
    `<a href="${item.href}"${item.attrs ? ` ${item.attrs}` : ""}>${item.label}</a>`;
  const renderNavLinks = (items: Array<AdminNavItem | false | null | undefined>) =>
    items
      .filter((item): item is AdminNavItem => Boolean(item))
      .map(navLink)
      .join("");
  const renderSections = (sections: Array<AdminSection | false | null | undefined>) =>
    sections
      .filter((section): section is AdminSection => Boolean(section))
      .map((section) =>
        [
          `<div class="section-tabs" data-section="${section.group}">`,
          ...section.links.map((link) => (typeof link === "string" ? link : sectionLink(link))),
          "</div>"
        ].join("")
      )
      .join("");
  const primaryTodayHref =
    sess && permLike && typeof activeWs !== "undefined"
      ? workspaceHomeUrl(activeWs, String(role ?? ""))
      : "/admin/profile";
  // Non-managers (FRONTDESK / HOUSEKEEPING / RESTAURANT) only ever see a personal
  // "Profile" entry; the full Settings group is reserved for managers/owners.
  const settingsNavItem: AdminNavItem = canSeeAdminSettings
    ? { group: "account", href: "/admin/setup", label: "Settings" }
    : { group: "account", href: "/admin/profile", label: "Profile" };
  const navHtml = authenticated
    ? role === "HOUSEKEEPING"
      ? renderNavLinks([
          { group: "dashboard", href: primaryTodayHref, label: "Today" },
          { group: "housekeeping", href: "/admin/housekeeping", label: "Housekeeping" },
          settingsNavItem
        ])
      : useOwnerChrome
        ? renderNavLinks([
            { group: "dashboard", href: "/admin/module/owner", label: "Today" },
            canNavBookings ? { group: "reservations", href: "/admin/bookings", label: "Reservations" } : false,
            canNavRooms ? { group: "frontdesk", href: "/admin/room-board", label: "Front Desk" } : false,
            canNavRooms ? { group: "inventory", href: "/admin/rooms", label: "Rooms &amp; Rates" } : false,
            canNavHousekeeping ? { group: "housekeeping", href: "/admin/housekeeping", label: "Housekeeping" } : false,
            canNavComms ? { group: "comms", href: "/admin/conversations", label: "WhatsApp Center" } : false,
            canNavFb ? { group: "fb", href: "/admin/fb/menu", label: "Restaurant &amp; Café" } : false,
            canNavReports ? { group: "insights", href: "/admin/reports-center", label: "Reports" } : false,
            settingsNavItem
          ])
        : useRestaurantChrome
          ? renderNavLinks([
              { group: "dashboard", href: "/admin/module/restaurant", label: "Today" },
              canNavFb ? { group: "fb", href: "/admin/fb/menu", label: "Restaurant &amp; Café" } : false,
              settingsNavItem
            ])
          : useHousekeepingManagerChrome
            ? renderNavLinks([
                { group: "dashboard", href: "/admin/module/housekeeping", label: "Today" },
                { group: "housekeeping", href: "/admin/housekeeping", label: "Housekeeping" },
                canNavRooms ? { group: "frontdesk", href: "/admin/room-board", label: "Room grid" } : false,
                settingsNavItem
              ])
            : useFrontDeskChrome
              ? renderNavLinks([
                  { group: "dashboard", href: primaryTodayHref, label: "Today" },
                  canNavBookings ? { group: "reservations", href: "/admin/bookings", label: "Reservations" } : false,
                  canNavRooms ? { group: "frontdesk", href: "/admin/room-board", label: "Front Desk" } : false,
                  // FRONTDESK does not manage rates / inventory; that surface is reserved for
                  // OWNER / MANAGER chromes (revenue management). Best-practice parity with
                  // Opera / Cloudbeds / Mews / eZee receptionist sidebars.
                  canSeeAdminSettings && canNavRooms
                    ? { group: "inventory", href: "/admin/rooms", label: "Rooms &amp; Rates" }
                    : false,
                  canNavHousekeeping ? { group: "housekeeping", href: "/admin/housekeeping", label: "Housekeeping" } : false,
                  canNavComms ? { group: "comms", href: "/admin/conversations", label: "WhatsApp Center" } : false,
                  canNavFb ? { group: "fb", href: "/admin/fb/menu", label: "Restaurant &amp; Café" } : false,
                  canNavReports ? { group: "insights", href: "/admin/reports-center", label: "Reports" } : false,
                  settingsNavItem
                ])
              : renderNavLinks([
                  { group: "dashboard", href: primaryTodayHref, label: "Today" },
                  canNavBookings ? { group: "reservations", href: "/admin/bookings", label: "Reservations" } : false,
                  canNavRooms ? { group: "frontdesk", href: "/admin/room-board", label: "Front Desk" } : false,
                  canSeeAdminSettings && canNavRooms
                    ? { group: "inventory", href: "/admin/rooms", label: "Rooms &amp; Rates" }
                    : false,
                  canNavHousekeeping ? { group: "housekeeping", href: "/admin/housekeeping", label: "Housekeeping" } : false,
                  canNavComms ? { group: "comms", href: "/admin/conversations", label: "WhatsApp Center" } : false,
                  canNavFb ? { group: "fb", href: "/admin/fb/menu", label: "Restaurant &amp; Café" } : false,
                  canNavReports ? { group: "insights", href: "/admin/reports-center", label: "Reports" } : false,
                  settingsNavItem
                ])
    : "";
  /// PMS UX cleanup: the dedicated "Workspaces" picker page duplicated sidebar groups
  /// (Today / Restaurant / Housekeeping / Owner), creating two competing nav systems.
  /// We removed the picker entry button entirely; the sidebar is now the only operational
  /// navigation. The chrome variation (owner/front_desk/restaurant/housekeeping) still
  /// works internally — it just isn't user-switchable from the UI anymore.
  const userIdentityHtml =
    authenticated && sess
      ? `<div class="user-card" title="Signed-in staff identity">
          <strong>${escapeHtml(sess.staffName || sess.email)}</strong>
          <span>${escapeHtml(String(sess.role))} · ${escapeHtml(sess.email)}</span>
          <span>Hotel account: ${escapeHtml(sess.hotelAccountNumber ? `#${sess.hotelAccountNumber}` : "not assigned")}</span>
        </div>`
      : "";
  /// Property switcher relocated from the bottom of the sidebar (where it was confused
  /// with "Workspaces") to a top-of-sidebar slot directly under the hotel-card. The IDs
  /// (`adminPropertySwitchHost`, `adminPropertySwitch`) are unchanged so the existing
  /// `getAdminPropertySwitcherScript()` still toggles visibility and wires the dropdown
  /// without modification. Hidden until JS detects >1 accessible property.
  const propertySwitcherHtml = authenticated
    ? `<div id="adminPropertySwitchHost" class="sidebar-property-switch" hidden><label for="adminPropertySwitch">Property</label><select id="adminPropertySwitch"></select></div>`
    : "";
  const logoutHtml = authenticated
    ? `<form method="post" action="/admin/logout"><button type="submit">Logout</button></form>`
    : "";
  // Unauthenticated visitors (login / forgot-password / onboard) should see a
  // calm "auth landing" sidebar — no notification bell, no empty user/property
  // cards, no orphan logout button. Otherwise the chrome flickers between an
  // operator shell and a marketing splash, which previous users described as
  // the menu "messing up" after a failed login.
  const sidebarActionsHtml = authenticated
    ? `<div class="sidebar-actions">
        <div class="admin-notif-wrap">
          <button id="adminNotifBell" class="admin-notif-bell" type="button" title="Notifications">🔔</button>
          <span id="adminNotifBadge" class="admin-notif-badge" hidden>0</span>
          <div id="adminNotifPanel" class="admin-notif-panel" hidden>
            <div class="admin-notif-panel-head">
              <strong style="font-size:13px">Notifications</strong>
              <div class="admin-notif-actions">
                <button id="adminNotifMute" type="button" title="Mute alert sound">🔔</button>
                <button id="adminNotifReadAll" type="button">Read all</button>
              </div>
            </div>
            <div class="admin-notif-scroll">
              <ul id="adminNotifList" class="admin-notif-list"></ul>
              <p id="adminNotifEmpty" class="admin-notif-empty">No new notifications.</p>
            </div>
          </div>
        </div>
        <div class="sidebar-logout">${logoutHtml}</div>
      </div>`
    : "";
  // Hospitality PMS dedup: receptionists were seeing Room rack / Check-in / Check-out twice
  // (in Today and again in Front Desk). The "Today" group is now strictly the briefing surface
  // (Command center + Alerts). All operational actions live exclusively in the Front Desk group.
  const todayTabs: AdminSection = {
    group: "dashboard",
    links: [
      { href: primaryTodayHref, label: "Command center" },
      { href: "/admin/alert-center", label: "Alerts &amp; briefing" }
    ]
  };
  const reservationTabs: AdminSection = {
    group: "reservations",
    links: [
      ...(canNavBookings
        ? [
            { href: "/admin/bookings", label: "All reservations" },
            { href: "/admin/calendar", label: "Calendar" }
          ]
        : [])
    ]
  };
  // Front Desk owns ALL receptionist operational actions: Room rack, Check-in, Check-out,
  // Guest bills, plus the desk handover/shift workflow that was incorrectly under "Account".
  // Mirrors Cloudbeds / Mews / Opera front-desk navigation grouping.
  const frontDeskTabs: AdminSection = {
    group: "frontdesk",
    links: [
      ...(canNavRooms ? [{ href: "/admin/room-board", label: "Room rack" }] : []),
      ...(canCreateBookings ? [{ href: "/admin/front-desk/check-in", label: "Arrivals / check-in" }] : []),
      ...(canNavRooms ? [{ href: "/admin/front-desk/check-out", label: "Departures / check-out" }] : []),
      ...(canNavBookings
        ? [{ href: "/admin/bookings?view=checked-out&range=7d&rangeBy=checkOut&sort=checkout_desc", label: "Checked-out history" }]
        : []),
      ...(canNavBookings ? [{ href: "/admin/guests", label: "Guest CRM" }] : []),
      ...(canNavBookings ? [{ href: "/admin/bookings/search", label: "Guest bills &amp; folios" }] : []),
      ...(perm && hasPermission(perm, "ROOMS", "VIEW") ? [{ href: "/admin/handover-sheet", label: "Handover sheet" }] : []),
      ...(perm && hasPermission(perm, "BOOKINGS", "VIEW")
        ? [
            { href: "/admin/shift-close", label: "Shift close (cashier)" },
            { href: "/admin/shifts", label: "Shifts (history)" }
          ]
        : [])
    ]
  };
  const inventoryTabs: AdminSection = {
    group: "inventory",
    links: [
      { href: "/admin/rooms", label: "Room types &amp; units" },
      { href: "/admin/offers", label: "Pricing &amp; offers" },
      { href: "/admin/inventory", label: "Availability" },
      { href: "/admin/channel-control", label: "Channel control" }
    ]
  };
  const housekeepingTabs: AdminSection = {
    group: "housekeeping",
    links: [
      { href: "/admin/hk/room-board", label: "Room status" },
      { href: "/admin/housekeeping", label: "Cleaning tasks" },
      { href: "/admin/hk", label: "My tasks" },
      { href: "/admin/maintenance", label: "Maintenance" }
    ]
  };
  const guestMessageTabs: AdminSection = {
    group: "comms",
    links: [
      {
        href: "/admin/conversations",
        label: 'Conversations <span id="adminConvLiveBadge" class="nav-live-badge" hidden aria-live="polite">0</span>',
        attrs: "data-admin-conv-link"
      },
      { href: "/admin/whatsapp/templates", label: "Templates" },
      { href: "/admin/guest-guidebook", label: "Guest guidebook" },
      { href: "/admin/conversations/group-messages", label: "Guest messages (broadcast)" },
      { href: "/admin/whatsapp/failed-messages", label: "Failed messages" }
    ]
  };
  const foodBeverageTabs: AdminSection = {
    group: "fb",
    links: [
      { href: "/admin/module/restaurant", label: "Service today" },
      { href: "/admin/fb/menu", label: "Menu" },
      ...(canNavOutlet
        ? [
            { href: "/admin/outlet-dashboard", label: "Orders / KOT" },
            { href: "/admin/outlet-orders", label: "Order history" },
            { href: "/admin/restaurant-ops", label: "Operations guide" }
          ]
        : [])
    ]
  };
  // Reports group: every link here is hotel-scoped (filtered by activeHotelSlug()) and sits behind REPORTS:VIEW.
  // AI analytics / booking funnel / routing health used to be platform-acquisition-only in the sidebar but the
  // hotel-owner workspace landing card (/admin/module/owner) already advertised them; the route guards now mirror
  // REPORTS:VIEW so sidebar visibility, route protection, and workspace landing all agree.
  const reportTabs: AdminSection = {
    group: "insights",
    links: [
      { href: "/admin/reports-center", label: "Reports center" },
      { href: "/admin/management-kpi", label: "Revenue &amp; occupancy (KPI)" },
      { href: "/admin/daily-digest", label: "Daily digest" },
      { href: "/admin/feedback-dashboard", label: "Guest feedback" },
      { href: "/admin/payment-reconciliation", label: "Payment reconciliation" },
      { href: "/admin/ai-analytics", label: "AI analytics" },
      { href: "/admin/booking-funnel", label: "Booking funnel" },
      { href: "/admin/routing-health", label: "Routing health" }
    ]
  };
  // "Account / Settings" is for property + staff + finance configuration. Operational shift &
  // handover actions moved to the Front Desk group above (best practice: receptionist actions
  // belong in receptionist navigation, not under admin/settings).
  const adminTabs: AdminSection = {
    group: "account",
    links: [
      { href: "/admin/profile", label: "Hotel profile &amp; status" },
      { href: "/admin/setup", label: "Property setup" },
      { href: "/admin/knowledge-bank", label: "Knowledge bank" },
      ...(sess && isPlatformAcquisitionSession(sess)
        ? [{ href: "/admin/leads", label: "Partner CRM" }]
        : []),
      ...(perm && hasPermission(perm, "USERS", "VIEW") ? [{ href: "/admin/users", label: "Staff &amp; permissions" }] : []),
      ...(perm && hasPermission(perm, "USERS", "VIEW") ? [{ href: "/admin/audit-trail", label: "Audit trail" }] : []),
      ...(perm && hasPermission(perm, "BILLING", "VIEW")
        ? [
            { href: "/admin/billing", label: "Billing" },
            { href: "/admin/subscription", label: "Subscription" }
          ]
        : []),
      { href: "/admin/integrations", label: "Integrations" }
    ]
  };
  // Slim "Profile" group for FRONTDESK / RESTAURANT / HOUSEKEEPING staff sessions.
  // No property setup, no staff/permissions, no billing — those are managerial. Mirrors
  // Cloudbeds / Mews / eZee staff "Profile" surface (sign-out is handled in the sidebar).
  const personalAccountTabs: AdminSection = {
    group: "account",
    links: [{ href: "/admin/profile", label: "My profile" }]
  };
  const accountTabsForChrome = canSeeAdminSettings ? adminTabs : personalAccountTabs;
  const showFrontDeskSection = canNavRooms || canCreateBookings || canNavBookings;
  /// One unified sidebar for hotel staff & managers. Reports + Settings are universal,
  /// gated by their respective permissions (REPORTS:VIEW, USERS:VIEW, BILLING:VIEW) so a
  /// receptionist (FRONTDESK) does not see Reports while a MANAGER does — without forcing
  /// either to switch "workspace" to find them. This eliminates the second nav system the
  /// old workspace picker created (Today / Restaurant / Housekeeping / Owner cards that
  /// duplicated sidebar groups).
  // FRONTDESK chrome: receptionist surface — reservations, front desk operations,
  // housekeeping awareness, guest comms. NO inventory/rate management (managerial).
  const fdTabs = renderSections([
    todayTabs,
    canNavBookings ? reservationTabs : false,
    showFrontDeskSection ? frontDeskTabs : false,
    canSeeAdminSettings && canNavRooms ? inventoryTabs : false,
    canNavHousekeeping ? housekeepingTabs : false,
    canNavComms ? guestMessageTabs : false,
    canNavFb ? foodBeverageTabs : false,
    canNavReports ? reportTabs : false,
    accountTabsForChrome
  ]);
  const ownerTabs = renderSections([
    todayTabs,
    perm && hasPermission(perm, "BOOKINGS", "VIEW") ? reservationTabs : false,
    perm &&
    (hasPermission(perm, "ROOMS", "VIEW") ||
      hasPermission(perm, "BOOKINGS", "CREATE") ||
      hasPermission(perm, "BOOKINGS", "VIEW"))
      ? frontDeskTabs
      : false,
    perm && hasPermission(perm, "ROOMS", "VIEW") ? inventoryTabs : false,
    canNavReports ? reportTabs : false,
    adminTabs
  ]);
  const restaurantTabs = renderSections([todayTabs, foodBeverageTabs, accountTabsForChrome]);
  const hkManagerTabs = renderSections([
    todayTabs,
    {
      group: "housekeeping",
      links: [{ href: "/admin/housekeeping", label: "Cleaning queue" }]
    },
    // Room board + handover live in the front-desk group per `groupByPath` in
    // layout.html; keeping them in the same `frontdesk` group here ensures the
    // section-tab strip highlights correctly when an HK manager opens those pages.
    {
      group: "frontdesk",
      links: [
        { href: "/admin/room-board", label: "Room board" },
        ...(perm && hasPermission(perm, "BOOKINGS", "VIEW") ? [{ href: "/admin/handover-sheet", label: "Handover" }] : [])
      ]
    },
    accountTabsForChrome
  ]);
  const fullTabs = renderSections([
    todayTabs,
    canNavBookings ? reservationTabs : false,
    showFrontDeskSection ? frontDeskTabs : false,
    canSeeAdminSettings && canNavRooms ? inventoryTabs : false,
    canNavHousekeeping ? housekeepingTabs : false,
    canNavComms ? guestMessageTabs : false,
    canNavFb ? foodBeverageTabs : false,
    canNavReports ? reportTabs : false,
    accountTabsForChrome
  ]);
  const sectionTabsHtml = authenticated
    ? useOwnerChrome
      ? ownerTabs
      : useRestaurantChrome
        ? restaurantTabs
        : useHousekeepingManagerChrome
          ? hkManagerTabs
          : useFrontDeskChrome
            ? fdTabs
            : fullTabs
    : "";
  const langSwitcherHtml = '<a href="?lang=en" data-lang-link="en">EN</a><a href="?lang=ar" data-lang-link="ar">AR</a>';

  return layout
    .replace("{{uiErrorContextAttrs}}", uiErrorContextAttrs)
    .replaceAll("{{lang}}", "en")
    .replaceAll("{{dir}}", "ltr")
    .replaceAll("{{adminTitle}}", "ChatStay Admin")
    .replace("{{brandTagline}}", "WhatsApp-first booking ops")
    .replace("{{langSwitcher}}", langSwitcherHtml)
    .replace("{{sidebarActions}}", sidebarActionsHtml)
    .replace("{{hotelCard}}", hotelCardHtml)
    .replace("{{propertySwitcher}}", propertySwitcherHtml)
    .replace("{{userIdentity}}", userIdentityHtml)
    .replace("{{navLinks}}", navHtml)
    .replace("{{sectionTabs}}", sectionTabsHtml)
    .replace("{{logoutAction}}", logoutHtml)
    .replace("{{content}}", content)
    .replace(
      "{{extraScripts}}",
      getPasswordRevealScript() +
        (authenticated ? getBackForwardCacheGuardScript() + getAdminLiveScript() + getAdminNotificationScript() + getAdminPropertySwitcherScript() : "")
    );
}

function getAdminPropertySwitcherScript(): string {
  return `<script>
(function () {
  var host = document.getElementById("adminPropertySwitchHost");
  var select = document.getElementById("adminPropertySwitch");
  if (!host || !select) return;
  var currentPropertyId = "";

  function withPropertyId(url) {
    try {
      var u = new URL(url, window.location.origin);
      if (currentPropertyId) u.searchParams.set("propertyId", currentPropertyId);
      return u.pathname + u.search + u.hash;
    } catch {
      return url;
    }
  }

  function decorateLinksAndForms() {
    if (!currentPropertyId) return;
    document.querySelectorAll('a[href^="/admin/"]').forEach(function (a) {
      var href = a.getAttribute("href");
      if (!href || href.includes("propertyId=")) return;
      a.setAttribute("href", withPropertyId(href));
    });
    document.querySelectorAll('form[method="get"]').forEach(function (f) {
      var input = f.querySelector('input[name="propertyId"]');
      if (!input) {
        input = document.createElement("input");
        input.setAttribute("type", "hidden");
        input.setAttribute("name", "propertyId");
        f.appendChild(input);
      }
      input.value = currentPropertyId;
    });
  }

  fetch("/auth/property-context", { credentials: "same-origin", headers: { Accept: "application/json" } })
    .then(function (r) { return r.ok ? r.json() : null; })
    .then(function (data) {
      if (!data || !data.ok || !Array.isArray(data.properties) || data.properties.length <= 1) {
        return;
      }
      currentPropertyId = typeof data.activePropertyId === "string" ? data.activePropertyId : "";
      var allOpt = document.createElement("option");
      allOpt.value = "ALL";
      allOpt.textContent = "All Properties";
      if (currentPropertyId === "ALL") allOpt.selected = true;
      select.appendChild(allOpt);
      data.properties.forEach(function (p) {
        if (!p || typeof p.id !== "string") return;
        var opt = document.createElement("option");
        opt.value = p.id;
        var subtitle = p.city ? " (" + p.city + ")" : "";
        opt.textContent = (p.name || "Property") + subtitle;
        if (p.id === currentPropertyId) opt.selected = true;
        select.appendChild(opt);
      });
      host.removeAttribute("hidden");
      host.style.display = "";
      decorateLinksAndForms();
      select.addEventListener("change", function () {
        var nextId = String(select.value || "").trim();
        if (!nextId) return;
        fetch("/auth/property-context", {
          method: "POST",
          credentials: "same-origin",
          headers: { "Content-Type": "application/json", Accept: "application/json" },
          body: JSON.stringify({ propertyId: nextId })
        }).finally(function () {
          var u = new URL(window.location.href);
          u.searchParams.set("propertyId", nextId);
          window.location.assign(u.toString());
        });
      });
    })
    .catch(function () {});
})();
</script>`;
}

function renderHkLayout(params: { title: string; content: string; active: "tasks" | "board" }): string {
  const layout = readView("hk-layout.html");
  const hkSess = auditActorContext.getStore()?.session;
  const uiErrorContextAttrs = hkSess
    ? ` data-ui-user-id="${escapeHtml(hkSess.staffId)}" data-ui-role="${escapeHtml(String(hkSess.role))}" data-ui-hotel-slug="${escapeHtml(defaultHotelSlug)}"${
        hkSess.activePropertyId ? ` data-ui-property-id="${escapeHtml(String(hkSess.activePropertyId))}"` : ""
      }`
    : "";
  const tasksCls = params.active === "tasks" ? ' class="active"' : "";
  const boardCls = params.active === "board" ? ' class="active"' : "";
  const navLinks = `<a href="/admin/hk"${tasksCls}>My tasks</a><a href="/admin/hk/room-board"${boardCls}>Room board</a>`;
  const logoutForm = '<form method="post" action="/admin/logout"><button type="submit">Logout</button></form>';
  return layout
    .replace("{{uiErrorContextAttrs}}", uiErrorContextAttrs)
    .replace("{{pageTitle}}", escapeHtml(params.title))
    .replace("{{navLinks}}", navLinks)
    .replace("{{logoutForm}}", logoutForm)
    .replace("{{content}}", params.content)
    .replace("{{extraScripts}}", getAdminNotificationScript());
}

