authRouter.get("/property-context", async (req, res) => {
  const session = getSession(req);
  if (!session) {
    res.status(401).json({ ok: false, error: "unauthorized" });
    return;
  }
  const hotel = await getPlatformHotelBase();
  if (!hotel) {
    res.status(404).json({ ok: false, error: "hotel_not_found" });
    return;
  }
  // Property-context API only exposes ACTIVE properties — DRAFT/SUSPENDED/ARCHIVED are owner-console-only.
  const properties = await prisma.property.findMany({
    where: { hotelId: hotel.id, status: PropertyStatus.ACTIVE },
    select: { id: true, name: true, city: true },
    orderBy: { createdAt: "asc" }
  });
  const validIds = new Set(properties.map((p) => p.id));
  let activePropertyId = session.activePropertyId ?? null;
  if (activePropertyId === allPropertiesKey && properties.length > 1) {
    res.json({ ok: true, activePropertyId, properties });
    return;
  }
  if (!activePropertyId || !validIds.has(activePropertyId)) {
    activePropertyId = properties[0]?.id ?? null;
    session.activePropertyId = activePropertyId;
  }
  res.json({ ok: true, activePropertyId, properties });
});

authRouter.post("/property-context", async (req, res) => {
  const session = getSession(req);
  if (!session) {
    res.status(401).json({ ok: false, error: "unauthorized" });
    return;
  }
  const propertyId = String(req.body?.propertyId ?? "").trim();
  if (!propertyId) {
    res.status(400).json({ ok: false, error: "missing_property_id" });
    return;
  }
  const hotel = await getPlatformHotelBase();
  if (!hotel) {
    res.status(404).json({ ok: false, error: "hotel_not_found" });
    return;
  }
  if (propertyId === allPropertiesKey) {
    // "All properties" only makes sense when 2+ ACTIVE properties exist; non-ACTIVE properties are owner-console-only.
    const propertyCount = await prisma.property.count({
      where: { hotelId: hotel.id, status: PropertyStatus.ACTIVE }
    });
    if (propertyCount > 1) {
      session.activePropertyId = allPropertiesKey;
      res.json({ ok: true, activePropertyId: allPropertiesKey });
      return;
    }
  }
  // Refuse to switch into a non-ACTIVE property — DRAFT/SUSPENDED/ARCHIVED are not operational.
  const property = await prisma.property.findFirst({
    where: { id: propertyId, hotelId: hotel.id, status: PropertyStatus.ACTIVE },
    select: { id: true }
  });
  if (!property) {
    res.status(400).json({ ok: false, error: "invalid_property" });
    return;
  }
  session.activePropertyId = property.id;
  res.json({ ok: true, activePropertyId: property.id });
});

adminRouter.post("/logout", (req, res) => {
  const token = getSessionToken(req);
  if (token) activeSessions.delete(token);
  setProtectedNoStoreHeaders(res);
  res.setHeader(
    "Set-Cookie",
    `${sessionCookieName}=; HttpOnly; Path=/; Max-Age=0; Expires=Thu, 01 Jan 1970 00:00:00 GMT; SameSite=Lax`
  );
  res.redirect(303, "/admin/login");
});

function parsePermissionsFromBody(body: Record<string, unknown>): PermissionMatrix {
  const matrix = buildNoPermissions();
  for (const moduleName of permissionModules) {
    for (const action of permissionActions) {
      const key = `${moduleName}_${action}`;
      matrix[moduleName][action] = body[key] === "on";
    }
  }
  return matrix;
}

function renderPermissionBlocks(perms?: PermissionMatrix): string {
  const blocks = permissionModules
    .map(
      (moduleName) => `<fieldset style="border:1px solid #d8dee6; border-radius:10px; padding:10px">
  <legend style="padding:0 6px">${escapeHtml(permissionModuleLabels[moduleName])}</legend>
  <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:8px">
    <button type="button" class="btn-link" data-permission-module="${moduleName}" data-permission-level="none">None</button>
    <button type="button" class="btn-link" data-permission-module="${moduleName}" data-permission-level="view">View</button>
    <button type="button" class="btn-link" data-permission-module="${moduleName}" data-permission-level="operate">Operate</button>
    <button type="button" class="btn-link" data-permission-module="${moduleName}" data-permission-level="admin">Admin</button>
  </div>
  <label><input type="checkbox" name="${moduleName}_VIEW" ${perms?.[moduleName]?.VIEW ? "checked" : ""} /> View</label>
  <label style="margin-left:10px"><input type="checkbox" name="${moduleName}_EDIT" ${perms?.[moduleName]?.EDIT ? "checked" : ""} /> Edit</label>
  <label style="margin-left:10px"><input type="checkbox" name="${moduleName}_CREATE" ${perms?.[moduleName]?.CREATE ? "checked" : ""} /> Create</label>
  <label style="margin-left:10px"><input type="checkbox" name="${moduleName}_DELETE" ${perms?.[moduleName]?.DELETE ? "checked" : ""} /> Delete</label>
  <label style="margin-left:10px"><input type="checkbox" name="${moduleName}_MANAGE" ${perms?.[moduleName]?.MANAGE ? "checked" : ""} /> Manage</label>
</fieldset>`
    )
    .join("");
  return `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px">
  <button type="button" class="btn-link primary" data-permission-preset="FRONTDESK">Front desk preset</button>
  <button type="button" class="btn-link" data-permission-preset="HOUSEKEEPING">Housekeeping preset</button>
  <button type="button" class="btn-link" data-permission-preset="RESTAURANT">Restaurant/cafe preset</button>
  <button type="button" class="btn-link" data-permission-preset="FINANCE">Finance preset</button>
  <button type="button" class="btn-link" data-permission-preset="MANAGER">Manager full access</button>
  <button type="button" class="btn-link" data-permission-preset="NONE">Clear all</button>
</div>
<p class="muted" style="font-size:12px;margin-top:-4px">Fast setup: apply a role preset first. Use module buttons for exceptions: View = read only, Operate = normal daily work, Admin = full control for that module.</p>
${blocks}`;
}

function hotelUserPermissionKey(user: { email?: string | null; username?: string | null }): string {
  return String(user.email || user.username || "").trim().toLowerCase();
}

adminRouter.get("/users", requirePermission("USERS", "VIEW"), async (req, res) => {
  let users: Array<{
    id: string;
    fullName: string | null;
    email: string | null;
    username: string | null;
    role: UserRole | string | null;
    isActive: boolean | null;
  }> = [];
  try {
    const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() } });
    if (!hotel) {
      res.type("html").send(renderLayout("<h2>Users</h2><p>No hotel data found.</p>", true));
      return;
    }
    users = await prisma.hotelUser.findMany({
      where: { hotelId: hotel.id },
      orderBy: { createdAt: "desc" },
      select: {
        id: true,
        fullName: true,
        email: true,
        username: true,
        role: true,
        isActive: true
      }
    });
  } catch (err) {
    const fallback =
      "<h2>Users &amp; permissions</h2><p class=\"badge alert\">Users page is temporarily unavailable because the user table schema is out of date.</p><p>Please run the latest Prisma migrations, then reload this page.</p>";
    if (isHotelUserSchemaMismatchError(err)) {
      res.type("html").send(renderLayout(fallback, true));
      return;
    }
    console.error("Admin users page failed:", err instanceof Error ? err.message : String(err));
    res
      .status(500)
      .type("html")
      .send(renderLayout("<h2>Users &amp; permissions</h2><p class=\"badge alert\">Could not load users right now. Please try again.</p>", true));
    return;
  }
  const store = readPermissionStore();
  const created = req.query.created ? '<p class="badge ok">User created with permissions.</p>' : "";
  const updated = req.query.updated ? '<p class="badge ok">User details updated.</p>' : "";
  const resetSent = req.query.resetSent ? '<p class="badge ok">Password reset link sent to the registered email.</p>' : "";
  const deleted = req.query.deleted ? '<p class="badge ok">User deleted.</p>' : "";
  const deactivated = req.query.deactivated ? '<p class="badge ok">User had operation history, so the account was deactivated instead of deleted.</p>' : "";
  const userErrorNotice =
    req.query.error === "selfDelete"
      ? '<p class="badge alert">You cannot delete the account currently signed in.</p>'
      : req.query.error === "delete"
        ? '<p class="badge alert">Could not delete this user. Please try again.</p>'
        : "";

  const rows = users
    .map((user) => {
      const safeEmail = typeof user.email === "string" ? user.email : "";
      const safeUsername = typeof user.username === "string" ? user.username : "";
      const permKey = hotelUserPermissionKey(user);
      const roleKey = typeof user.role === "string" ? user.role : "MANAGER";
      const perms = normalizePermissionMatrix(store[permKey] ?? defaultPermissionsForRole(roleKey));
      const modulesSummary = permissionModules
        .filter((m) => perms[m].MANAGE || perms[m].VIEW || perms[m].EDIT || perms[m].CREATE || perms[m].DELETE)
        .map((m) => permissionModuleLabels[m])
        .join(", ");
      const roleOptions = ["OWNER", "MANAGER", "STAFF", "FRONTDESK", "FINANCE", "HOUSEKEEPING", "RESTAURANT"]
        .map((role) => `<option value="${role}" ${role === roleKey ? "selected" : ""}>${role}</option>`)
        .join("");
      const editFormId = `edit-user-${escapeHtml(user.id)}`;
      return `<tr>
      <td>${escapeHtml(typeof user.fullName === "string" ? user.fullName : "—")}</td>
      <td>${escapeHtml((typeof user.email === "string" && user.email) || (typeof user.username === "string" && user.username) || "—")}</td>
      <td>${escapeHtml(roleKey)}</td>
      <td>${user.isActive ? '<span class="badge ok">Active</span>' : '<span class="badge alert">Disabled</span>'}</td>
      <td>${escapeHtml(modulesSummary || "No permissions set")}</td>
      <td><button type="button" class="btn-link" onclick="var el=document.getElementById('${editFormId}'); if(el) el.hidden=!el.hidden;">Edit</button></td>
      </tr>
      <tr id="${editFormId}" hidden>
        <td colspan="6">
          <form method="post" action="/admin/users/${encodeURIComponent(user.id)}" style="display:grid;gap:10px;padding:12px;border:1px solid #d8dee6;border-radius:12px;background:#f8fafc">
            <div class="grid-2">
              <label>Full name<br /><input type="text" name="fullName" value="${escapeHtml(user.fullName ?? "")}" required style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
              <label>Email<br /><input type="email" name="email" value="${escapeHtml(safeEmail)}" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
              <label>Username<br /><input type="text" name="username" value="${escapeHtml(safeUsername)}" maxlength="64" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
              <label>Role
                <select name="role" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px">${roleOptions}</select>
              </label>
              <label>New password (leave blank to keep current)<br /><input type="password" name="password" minlength="8" autocomplete="new-password" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
              <label>New PIN (leave blank to keep current)<br /><input type="password" name="pin" minlength="4" maxlength="12" autocomplete="new-password" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
              <label style="align-self:end"><input type="checkbox" name="isActive" value="1" ${user.isActive ? "checked" : ""} /> Active user</label>
            </div>
            <h4 style="margin:6px 0 0">Permissions</h4>
            <div style="display:grid; gap:8px">${renderPermissionBlocks(perms)}</div>
            <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
              <button type="submit" style="padding:9px 13px; border:0; border-radius:8px; background:#0b6e6e; color:#fff; font-weight:700">Save user details</button>
              ${safeEmail ? `<button type="submit" formaction="/admin/users/${encodeURIComponent(user.id)}/send-reset" style="padding:9px 13px; border:0; border-radius:8px; background:#25d366; color:#083d2d; font-weight:700">Send password reset email</button>` : ""}
              <button type="submit" formaction="/admin/users/${encodeURIComponent(user.id)}/delete" onclick="return confirm('Delete this user account? If the user has operation history, the account will be deactivated instead to preserve audit records.')" style="padding:9px 13px; border:0; border-radius:8px; background:#fee2e2; color:#991b1b; font-weight:700">Delete user</button>
            </div>
          </form>
        </td>
      </tr>`;
    })
    .join("");

  const modulePermissionBlocks = renderPermissionBlocks();

  const content = `
<h2>Users &amp; permissions</h2>
<p class="muted">Create and edit hotel staff accounts. Best practice is password reset by registered email, but management can also directly update username, role, permissions, active status, password, or PIN when operations need an immediate fix.</p>
${created}${updated}${resetSent}${deleted}${deactivated}${userErrorNotice}
<div class="actions">
  <a class="btn-link primary" href="/admin/profile">Back to profile</a>
</div>
<section style="margin-top:12px">
  <h3>Create user</h3>
  <p id="admin-create-user-error" class="badge alert" style="display:none; margin-bottom:8px" role="alert"></p>
  <form id="admin-create-user-form" method="post" action="/admin/users" style="display:grid; gap:10px">
    <div class="grid-2">
      <label>Full name<br /><input type="text" name="fullName" required style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
      <label>Email (optional for housekeeping)<br /><input type="email" name="email" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
      <label>Username (optional — staff / housekeeping mobile sign-in)<br /><input type="text" name="username" maxlength="64" placeholder="e.g. hk-01" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
      <label>Password<br /><input type="password" name="password" minlength="8" required style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
      <label>PIN (optional — used with username for housekeeping staff sign-in)<br /><input type="password" name="pin" minlength="4" maxlength="12" placeholder="4-12 digits" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px" /></label>
      <label>Role
        <select name="role" style="width:100%; padding:8px; border:1px solid #d8dee6; border-radius:8px">
          <option value="MANAGER">MANAGER</option>
          <option value="STAFF">STAFF</option>
          <option value="FRONTDESK">FRONTDESK</option>
          <option value="FINANCE">FINANCE</option>
          <option value="HOUSEKEEPING">HOUSEKEEPING</option>
          <option value="RESTAURANT">RESTAURANT / CAFÉ</option>
        </select>
      </label>
    </div>
    <h4 style="margin:6px 0 0">Permissions</h4>
    <div style="display:grid; gap:8px">${modulePermissionBlocks}</div>
    <button type="submit" style="padding:10px 14px; border:0; border-radius:10px; background:#0b6e6e; color:#fff; font-weight:700; width:max-content">Create user</button>
  </form>
  <script>
  (function () {
    var form = document.getElementById("admin-create-user-form");
    var errEl = document.getElementById("admin-create-user-error");
    if (!form) return;
    form.addEventListener("submit", function (e) {
      e.preventDefault();
      if (errEl) { errEl.style.display = "none"; errEl.textContent = ""; }
      var fd = new FormData(form);
      var params = new URLSearchParams();
      fd.forEach(function (v, k) { params.append(k, v); });
      fetch("/admin/users", {
        method: "POST",
        headers: { Accept: "application/json", "Content-Type": "application/x-www-form-urlencoded" },
        body: params.toString(),
        credentials: "same-origin"
      })
        .then(function (r) {
          return r
            .json()
            .catch(function () {
              return {};
            })
            .then(function (data) {
              return { r: r, data: data };
            });
        })
        .then(function (o) {
          if (o.r.ok && o.data && o.data.success === true) {
            window.location.href = "/admin/users?created=1";
            return;
          }
          var msg = (o.data && o.data.error) ? String(o.data.error) : "Could not create user.";
          if (errEl) { errEl.textContent = msg; errEl.style.display = "block"; }
          else { alert(msg); }
        })
        .catch(function () {
          var msg = "Network error. Please try again.";
          if (errEl) { errEl.textContent = msg; errEl.style.display = "block"; }
          else { alert(msg); }
        });
    });
  })();
  (function () {
    var modules = ${JSON.stringify(permissionModules)};
    var actions = ${JSON.stringify(permissionActions)};
    function setChecked(form, moduleName, action, value) {
      var input = form.querySelector('input[name="' + moduleName + '_' + action + '"]');
      if (input) input.checked = Boolean(value);
    }
    function setModuleLevel(form, moduleName, level) {
      var enabled = {
        none: [],
        view: ["VIEW"],
        operate: ["VIEW", "EDIT", "CREATE"],
        admin: ["VIEW", "EDIT", "CREATE", "DELETE", "MANAGE"]
      }[level] || [];
      actions.forEach(function (action) {
        setChecked(form, moduleName, action, enabled.indexOf(action) !== -1);
      });
    }
    function clearAll(form) {
      modules.forEach(function (moduleName) { setModuleLevel(form, moduleName, "none"); });
    }
    function applyPreset(form, preset) {
      clearAll(form);
      if (preset === "MANAGER") {
        modules.forEach(function (moduleName) { setModuleLevel(form, moduleName, "admin"); });
        return;
      }
      if (preset === "FRONTDESK") {
        setModuleLevel(form, "ROOMS", "operate");
        setModuleLevel(form, "BOOKINGS", "operate");
        setModuleLevel(form, "CONVERSATIONS", "operate");
        setModuleLevel(form, "REPORTS", "view");
        setModuleLevel(form, "BILLING", "view");
        return;
      }
      if (preset === "HOUSEKEEPING") {
        setModuleLevel(form, "HOUSEKEEPING", "operate");
        setModuleLevel(form, "ROOMS", "operate");
        return;
      }
      if (preset === "RESTAURANT") {
        setModuleLevel(form, "OUTLET", "operate");
        return;
      }
      if (preset === "FINANCE") {
        setModuleLevel(form, "BILLING", "operate");
        setModuleLevel(form, "REPORTS", "view");
        setModuleLevel(form, "BOOKINGS", "view");
      }
    }
    document.addEventListener("click", function (ev) {
      var btn = ev.target && ev.target.closest ? ev.target.closest("[data-permission-preset], [data-permission-module]") : null;
      if (!btn) return;
      var form = btn.closest("form");
      if (!form) return;
      ev.preventDefault();
      var preset = btn.getAttribute("data-permission-preset");
      if (preset) applyPreset(form, preset);
      var moduleName = btn.getAttribute("data-permission-module");
      var level = btn.getAttribute("data-permission-level");
      if (moduleName && level) setModuleLevel(form, moduleName, level);
    });
  })();
  </script>
</section>
<section style="margin-top:14px">
  <h3>Existing users</h3>
  <table>
    <thead><tr><th>Name</th><th>Email / username</th><th>Role</th><th>Status</th><th>Permission modules</th><th>Actions</th></tr></thead>
    <tbody>${rows || '<tr><td colspan="6">No users yet.</td></tr>'}</tbody>
  </table>
</section>`;
  res.type("html").send(renderLayout(content, true));
});

adminRouter.get("/feedback-dashboard", requirePermission("REPORTS", "VIEW"), async (_req, res) => {
  const hotel = await prisma.hotel.findUnique({
    where: { slug: activeHotelSlug() },
    select: { id: true, displayName: true }
  });
  if (!hotel) {
    res.redirect("/admin/login");
    return;
  }
  let data: FeedbackDashboardData | null = null;
  try {
    data = await loadFeedbackDashboard(prisma, hotel.id);
  } catch (err) {
    console.error(
      "[admin] /feedback-dashboard load failed:",
      err instanceof Error ? err.stack ?? err.message : String(err)
    );
  }
  if (!data) {
    res
      .type("html")
      .send(
        renderLayout(
          `<h2>Guest Feedback</h2><p class="muted">Could not load feedback right now. Try again in a moment.</p>`,
          true
        )
      );
    return;
  }
  res.type("html").send(renderLayout(renderFeedbackDashboardPage(hotel.displayName, data), true));
});

async function loadFeedbackForAction(feedbackId: string) {
  const hotel = await prisma.hotel.findUnique({
    where: { slug: activeHotelSlug() },
    select: { id: true, displayName: true }
  });
  if (!hotel) return null;
  const feedback = await prisma.guestFeedback.findFirst({
    where: { id: feedbackId, hotelId: hotel.id },
    include: { booking: { include: { guest: true } }, guest: true }
  });
  if (!feedback) return null;
  return { hotel, feedback };
}

adminRouter.post("/feedback-dashboard/:feedbackId/contacted", requirePermission("REPORTS", "EDIT"), async (req, res) => {
  const ctx = await loadFeedbackForAction(String(req.params.feedbackId ?? ""));
  if (ctx) {
    await prisma.guestFeedback.update({
      where: { id: ctx.feedback.id },
      data: {
        managerFollowUpRequestedAt: ctx.feedback.managerFollowUpRequestedAt ?? new Date(),
        lowRatingAlertedAt: ctx.feedback.lowRatingAlertedAt ?? new Date()
      }
    });
    await logAudit({
      hotelId: ctx.hotel.id,
      action: "FEEDBACK_RECOVERY_CONTACTED",
      entityType: "GuestFeedback",
      entityId: ctx.feedback.id,
      metadata: { bookingId: ctx.feedback.bookingId, rating: ctx.feedback.rating }
    });
  }
  res.redirect("/admin/feedback-dashboard");
});

adminRouter.post("/feedback-dashboard/:feedbackId/resolve", requirePermission("REPORTS", "EDIT"), async (req, res) => {
  const ctx = await loadFeedbackForAction(String(req.params.feedbackId ?? ""));
  if (ctx) {
    await prisma.guestFeedback.update({
      where: { id: ctx.feedback.id },
      data: { managerFollowUpClosedAt: new Date(), status: GuestFeedbackStatus.COMPLETED }
    });
    await logAudit({
      hotelId: ctx.hotel.id,
      action: "FEEDBACK_RECOVERY_RESOLVED",
      entityType: "GuestFeedback",
      entityId: ctx.feedback.id,
      metadata: { bookingId: ctx.feedback.bookingId, rating: ctx.feedback.rating }
    });
  }
  res.redirect("/admin/feedback-dashboard");
});

adminRouter.post("/feedback-dashboard/:feedbackId/send-recovery", requirePermission("CONVERSATIONS", "EDIT"), async (req, res) => {
  const ctx = await loadFeedbackForAction(String(req.params.feedbackId ?? ""));
  if (ctx) {
    const guest = ctx.feedback.guest ?? ctx.feedback.booking.guest;
    const phone = guest.phoneE164.replace(/\D/g, "");
    if (phone) {
      const config = loadPartnerSetupConfig(ctx.hotel.id);
      await sendWhatsAppText({
        to: phone,
        phoneNumberId: config.whatsappPhoneNumberId || undefined,
        body: `${ctx.hotel.displayName}: Thank you for your feedback. We are sorry your stay was not perfect. A manager will review this personally and follow up with you.`
      });
      await prisma.guestFeedback.update({
        where: { id: ctx.feedback.id },
        data: { managerFollowUpRequestedAt: ctx.feedback.managerFollowUpRequestedAt ?? new Date(), lowRatingAlertedAt: ctx.feedback.lowRatingAlertedAt ?? new Date() }
      });
      await logAudit({
        hotelId: ctx.hotel.id,
        action: "FEEDBACK_RECOVERY_WHATSAPP_SENT",
        entityType: "GuestFeedback",
        entityId: ctx.feedback.id,
        metadata: { bookingId: ctx.feedback.bookingId, rating: ctx.feedback.rating }
      });
    }
  }
  res.redirect("/admin/feedback-dashboard");
});

adminRouter.post("/feedback-dashboard/:feedbackId/send-public-review", requirePermission("CONVERSATIONS", "EDIT"), async (req, res) => {
  const ctx = await loadFeedbackForAction(String(req.params.feedbackId ?? ""));
  if (ctx) {
    const config = loadPartnerSetupConfig(ctx.hotel.id);
    const guest = ctx.feedback.guest ?? ctx.feedback.booking.guest;
    const phone = guest.phoneE164.replace(/\D/g, "");
    if (phone && config.googleReviewLink) {
      await sendWhatsAppText({
        to: phone,
        phoneNumberId: config.whatsappPhoneNumberId || undefined,
        body: `${ctx.hotel.displayName}: Thank you for your kind feedback. If you have a moment, please share your experience publicly here: ${config.googleReviewLink}`
      });
      await prisma.guestFeedback.update({
        where: { id: ctx.feedback.id },
        data: { publicReviewClickedAt: ctx.feedback.publicReviewClickedAt ?? new Date(), isHappyGuest: true, isPromoter: ctx.feedback.rating >= 5 }
      });
      await logAudit({
        hotelId: ctx.hotel.id,
        action: "FEEDBACK_PUBLIC_REVIEW_REQUEST_SENT",
        entityType: "GuestFeedback",
        entityId: ctx.feedback.id,
        metadata: { bookingId: ctx.feedback.bookingId, rating: ctx.feedback.rating }
      });
    }
  }
  res.redirect("/admin/feedback-dashboard");
});

adminRouter.get("/audit-trail", requirePermission("USERS", "VIEW"), async (req, res) => {
  const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() }, select: { id: true, displayName: true } });
  if (!hotel) {
    res.redirect("/admin/login");
    return;
  }
  const actor = String(req.query.actor ?? "").trim();
  const categoryFilter = String(req.query.category ?? "").trim();
  const search = String(req.query.q ?? "").trim();
  const takeRaw = Number.parseInt(String(req.query.take ?? "150"), 10);
  const take = Number.isFinite(takeRaw) ? Math.max(25, Math.min(500, takeRaw)) : 150;
  const andFilters: Prisma.AuditLogWhereInput[] = [];
  if (actor) andFilters.push({ OR: [{ actorEmail: { contains: actor } }, { actorUserId: { contains: actor } }] });
  if (search) {
    andFilters.push({
      OR: [
        { action: { contains: search.toUpperCase() } },
        { entityType: { contains: search } },
        { entityId: { contains: search } },
        { metadataJson: { contains: search } }
      ]
    });
  }
  const where: Prisma.AuditLogWhereInput = {
    hotelId: hotel.id,
    ...(andFilters.length ? { AND: andFilters } : {})
  };
  const logs = await prisma.auditLog.findMany({
    where,
    orderBy: { createdAt: "desc" },
    take
  });

  // Map to friendly lines, then optionally filter by category client-side
  // (the friendly category isn't a column in AuditLog — it's derived).
  type Enriched = {
    id: string;
    createdAt: Date;
    actorEmail: string;
    actorUserId: string | null;
    action: string;
    entityType: string;
    entityId: string | null;
    line: FriendlyAuditLine;
  };
  const enriched: Enriched[] = logs.map((log) => {
    const metadata = parseAuditMetadata(log.metadataJson);
    return {
      id: log.id,
      createdAt: log.createdAt,
      actorEmail: log.actorEmail ?? "",
      actorUserId: log.actorUserId,
      action: log.action,
      entityType: log.entityType,
      entityId: log.entityId,
      line: describeAuditAction(log.action, metadata, log.entityType)
    };
  });
  const filtered =
    categoryFilter && AUDIT_CATEGORY_LIST.includes(categoryFilter as AuditCategory)
      ? enriched.filter((e) => e.line.category === categoryFilter)
      : enriched;

  // Group by day so the timeline reads top-down like a journal.
  const groupKey = (d: Date) => {
    const local = new Date(d);
    return `${local.getFullYear()}-${String(local.getMonth() + 1).padStart(2, "0")}-${String(local.getDate()).padStart(2, "0")}`;
  };
  const grouped = new Map<string, Enriched[]>();
  for (const row of filtered) {
    const key = groupKey(row.createdAt);
    const existing = grouped.get(key) ?? [];
    existing.push(row);
    grouped.set(key, existing);
  }
  const dayHeading = (key: string): string => {
    const [y, m, d] = key.split("-").map((p) => Number.parseInt(p, 10));
    if (Number.isNaN(y)) return key;
    const date = new Date(y, m - 1, d);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const yesterday = new Date(today);
    yesterday.setDate(today.getDate() - 1);
    if (date.getTime() === today.getTime()) return "Today";
    if (date.getTime() === yesterday.getTime()) return "Yesterday";
    return date.toLocaleDateString(undefined, { weekday: "long", day: "numeric", month: "short", year: "numeric" });
  };

  const initials = (email: string, fallbackUserId: string | null): string => {
    const handle = email.split("@")[0] || fallbackUserId || "S";
    const parts = handle.split(/[._-]/).filter(Boolean);
    if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
    return (handle.slice(0, 2) || "S").toUpperCase();
  };
  const friendlyName = (email: string, fallbackUserId: string | null): string => {
    if (email && email !== "system@chatastay.local") return email.split("@")[0];
    if (fallbackUserId === "SYSTEM" || !fallbackUserId) return "System";
    return fallbackUserId;
  };
  const relativeTime = (date: Date, now: Date): string => {
    const diffMs = now.getTime() - date.getTime();
    const diffMin = Math.round(diffMs / 60000);
    if (diffMin < 1) return "just now";
    if (diffMin < 60) return `${diffMin} min ago`;
    const diffHr = Math.round(diffMin / 60);
    if (diffHr < 24) return `${diffHr} h ago`;
    const diffDay = Math.round(diffHr / 24);
    if (diffDay < 7) return `${diffDay} d ago`;
    return formatDateTime(date);
  };

  const now = new Date();
  const renderEntry = (e: Enriched): string => {
    const accentVar = `var(--accent-${e.line.accent})`;
    const detail = e.line.detail ? `<div class="audit-detail">${escapeHtml(e.line.detail)}</div>` : "";
    return `<li class="audit-item">
      <span class="audit-dot" style="background:${accentVar}"></span>
      <span class="audit-icon" aria-hidden="true">${e.line.icon}</span>
      <div class="audit-body">
        <div class="audit-meta">
          <span class="audit-avatar" title="${escapeHtml(e.actorEmail || friendlyName(e.actorEmail, e.actorUserId))}">${escapeHtml(initials(e.actorEmail, e.actorUserId))}</span>
          <span class="audit-actor">${escapeHtml(friendlyName(e.actorEmail, e.actorUserId))}</span>
          <span class="audit-tag" style="background:${accentVar}1a;color:${accentVar}">${escapeHtml(e.line.category)}</span>
          <time class="audit-time" datetime="${e.createdAt.toISOString()}" title="${formatDateTime(e.createdAt)}">${escapeHtml(relativeTime(e.createdAt, now))}</time>
        </div>
        <div class="audit-headline">${escapeHtml(e.line.headline)}</div>
        ${detail}
        <div class="audit-source">${e.entityType ? `<span>${escapeHtml(e.entityType)}</span>` : ""}${
          e.entityId ? ` <code>${escapeHtml(e.entityId.length > 14 ? e.entityId.slice(0, 14) + "…" : e.entityId)}</code>` : ""
        } <span class="muted">· ${escapeHtml(e.action.replace(/_/g, " ").toLowerCase())}</span></div>
      </div>
    </li>`;
  };

  const sortedKeys = Array.from(grouped.keys()).sort((a, b) => (a < b ? 1 : -1));
  const timelineHtml = sortedKeys.length
    ? sortedKeys
        .map(
          (key) =>
            `<section class="audit-day"><h3>${escapeHtml(dayHeading(key))}<span class="muted">${grouped.get(key)?.length ?? 0} ${
              (grouped.get(key)?.length ?? 0) === 1 ? "action" : "actions"
            }</span></h3><ul class="audit-list">${(grouped.get(key) ?? []).map(renderEntry).join("")}</ul></section>`
        )
        .join("")
    : `<div class="audit-empty"><p>No staff actions found for these filters yet.</p></div>`;

  // Top-of-page summary: who did what today
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const todayActions = enriched.filter((e) => e.createdAt >= today);
  const summaryByActor = new Map<string, { name: string; count: number; categories: Set<string> }>();
  for (const e of todayActions) {
    const key = e.actorEmail || e.actorUserId || "SYSTEM";
    const existing = summaryByActor.get(key) ?? { name: friendlyName(e.actorEmail, e.actorUserId), count: 0, categories: new Set<string>() };
    existing.count += 1;
    existing.categories.add(e.line.category);
    summaryByActor.set(key, existing);
  }
  const summaryRows = Array.from(summaryByActor.entries())
    .sort((a, b) => b[1].count - a[1].count)
    .slice(0, 6)
    .map(
      ([_key, v]) =>
        `<div class="audit-actor-pill"><span class="audit-avatar">${escapeHtml(v.name.slice(0, 2).toUpperCase())}</span><div><strong>${escapeHtml(v.name)}</strong><span class="muted">${v.count} ${v.count === 1 ? "action" : "actions"} · ${Array.from(v.categories).join(", ")}</span></div></div>`
    )
    .join("");

  const categoryOptions = AUDIT_CATEGORY_LIST.map(
    (c) => `<option value="${escapeHtml(c)}" ${categoryFilter === c ? "selected" : ""}>${escapeHtml(c)}</option>`
  ).join("");

  const styles = `<style>
    :root {
      --accent-green:#22c55e; --accent-blue:#3b82f6; --accent-amber:#f59e0b;
      --accent-purple:#a855f7; --accent-rose:#f43f5e; --accent-slate:#64748b;
      --accent-teal:#0d9488; --accent-sky:#0ea5e9;
    }
    .audit-hero { background:linear-gradient(135deg,#f8fafc 0%,#ecfdf5 100%); border:1px solid #d6ebe1; border-radius:18px; padding:18px 22px; margin-bottom:18px; }
    .audit-hero h2 { margin:0; font-size:22px; letter-spacing:-0.02em; color:#0b1f1c; }
    .audit-hero p { margin:6px 0 0; color:#475569; font-size:13.5px; }
    .audit-summary { display:flex; flex-wrap:wrap; gap:10px; margin-top:14px; }
    .audit-actor-pill { display:flex; align-items:center; gap:10px; background:#fff; border:1px solid #e2e8f0; border-radius:14px; padding:8px 14px; min-width:200px; box-shadow:0 6px 18px rgba(15,44,38,.04); }
    .audit-actor-pill .audit-avatar { background:#0f766e; color:#fff; width:32px; height:32px; border-radius:50%; display:inline-flex; align-items:center; justify-content:center; font-weight:800; font-size:12px; letter-spacing:0.04em; }
    .audit-actor-pill strong { display:block; color:#0f172a; font-size:13px; }
    .audit-actor-pill .muted { font-size:11.5px; color:#64748b; display:block; }
    .audit-filter-form { display:flex; flex-wrap:wrap; align-items:flex-end; gap:10px; margin:0 0 16px; padding:14px; background:#fff; border:1px solid #e2e8f0; border-radius:14px; }
    .audit-filter-form label { display:flex; flex-direction:column; gap:4px; font-size:12px; color:#475569; font-weight:600; }
    .audit-filter-form input, .audit-filter-form select { padding:9px 12px; border:1px solid #d8dee6; border-radius:10px; font-size:13.5px; }
    .audit-filter-form button { padding:9px 18px; border:0; border-radius:10px; background:#0f766e; color:#fff; font-weight:700; font-size:13.5px; cursor:pointer; }
    .audit-filter-form .btn-link { font-size:13px; color:#475569; text-decoration:none; padding:9px 12px; border-radius:10px; }
    .audit-filter-form .btn-link:hover { background:#f1f5f9; color:#0f766e; }
    .audit-day { margin-bottom:22px; }
    .audit-day > h3 { margin:0 0 12px; font-size:13px; color:#475569; text-transform:uppercase; letter-spacing:0.08em; font-weight:800; display:flex; align-items:center; gap:10px; }
    .audit-day > h3 .muted { font-weight:600; color:#94a3b8; text-transform:none; letter-spacing:0; }
    .audit-list { list-style:none; padding:0; margin:0; position:relative; }
    .audit-list::before { content:""; position:absolute; left:14px; top:18px; bottom:0; width:2px; background:linear-gradient(180deg,#e2e8f0,#f1f5f9); }
    .audit-item { position:relative; display:grid; grid-template-columns:30px auto 1fr; gap:12px; padding:14px 16px; background:#fff; border:1px solid #e2e8f0; border-radius:14px; margin-bottom:10px; box-shadow:0 6px 16px rgba(15,44,38,.04); }
    .audit-item .audit-dot { position:absolute; left:6px; top:24px; width:14px; height:14px; border-radius:50%; box-shadow:0 0 0 4px #fff; }
    .audit-icon { font-size:22px; align-self:center; }
    .audit-meta { display:flex; flex-wrap:wrap; align-items:center; gap:8px; margin-bottom:6px; font-size:12.5px; color:#64748b; }
    .audit-avatar { display:inline-flex; align-items:center; justify-content:center; width:24px; height:24px; border-radius:50%; background:#e2e8f0; color:#0f172a; font-size:11px; font-weight:800; }
    .audit-actor { font-weight:700; color:#0f172a; }
    .audit-tag { font-size:10.5px; font-weight:800; padding:2px 9px; border-radius:999px; letter-spacing:0.04em; text-transform:uppercase; }
    .audit-time { margin-left:auto; color:#94a3b8; font-size:12px; font-variant-numeric:tabular-nums; }
    .audit-headline { font-size:14.5px; color:#0f172a; font-weight:700; line-height:1.4; }
    .audit-detail { color:#475569; font-size:13px; line-height:1.45; margin-top:2px; }
    .audit-source { margin-top:8px; font-size:11.5px; color:#94a3b8; display:flex; align-items:center; gap:6px; flex-wrap:wrap; }
    .audit-source code { background:#f1f5f9; padding:1px 8px; border-radius:6px; color:#475569; font-size:11px; }
    .audit-source .muted { color:#cbd5e1; }
    .audit-empty { padding:48px 16px; text-align:center; color:#94a3b8; background:#fff; border:1px dashed #e2e8f0; border-radius:14px; }
    @media print {
      .audit-filter-form, .sidebar, .top-subnav { display:none !important; }
      .audit-item { break-inside:avoid; }
    }
  </style>`;

  const summaryBlock = summaryRows
    ? `<div class="audit-summary">${summaryRows}</div>`
    : `<div class="audit-summary"><p class="muted" style="margin:0">No staff activity recorded yet today.</p></div>`;

  const content = `${styles}
<div class="audit-hero">
  <h2>Staff Activity</h2>
  <p>A friendly diary of what your team did at ${escapeHtml(hotel.displayName)} — every check-in, payment, room status change, message, and login. Use the filters below to focus on a person or a workflow.</p>
  ${summaryBlock}
</div>
<form method="get" action="/admin/audit-trail" class="audit-filter-form">
  <label>Staff member<input name="actor" value="${escapeHtml(actor)}" placeholder="email or staff ID" /></label>
  <label>Workflow<select name="category"><option value="">All workflows</option>${categoryOptions}</select></label>
  <label>Search<input name="q" value="${escapeHtml(search)}" placeholder="booking ID, room, action…" /></label>
  <label>Show<input type="number" name="take" min="25" max="500" step="25" value="${take}" /></label>
  <button type="submit">Apply filters</button>
  <a class="btn-link" href="/admin/audit-trail">Reset</a>
  <button type="button" class="btn-link" onclick="window.print()">Print</button>
</form>
${timelineHtml}`;
  res.type("html").send(renderLayout(content, true));
});

adminRouter.post("/users", requireAuth, async (req, res) => {
  const jsonErr = (status: number, message: string) => {
    if (!res.headersSent) res.status(status).json({ error: message });
  };

  try {
    const session = getSession(req);
    const canCreateUsers =
      session != null &&
      (hasPermission(session.permissions, "USERS", "CREATE") ||
        (["MANAGER", "OWNER"].includes(String(session.role)) && hasPermission(session.permissions, "USERS", "VIEW")));
    if (!canCreateUsers) {
      jsonErr(403, "Your account can view staff but cannot create staff accounts. Ask an owner to grant Users: Create.");
      return;
    }

    const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() } });
    if (!hotel) {
      jsonErr(404, "Hotel not found.");
      return;
    }
    const planCtx = await loadHotelPlanContext(prisma, hotel.id);
    const activeStaffCount = await prisma.hotelUser.count({ where: { hotelId: hotel.id, isActive: true } });
    try {
      assertWithinLimit(planCtx, "maxStaffUsers", activeStaffCount + 1, "Staff user");
    } catch (limitErr) {
      jsonErr(403, upgradeMessage(limitErr instanceof Error ? limitErr.message : "Staff user limit reached."));
      return;
    }

    const fullName = String(req.body.fullName ?? "").trim();
    const emailRaw = String(req.body.email ?? "").trim().toLowerCase();
    const email = emailRaw || null;
    const username = String(req.body.username ?? "").trim().toLowerCase() || null;
    const password = String(req.body.password ?? "");
    const pin = String(req.body.pin ?? "").trim();
    const role = String(req.body.role ?? "MANAGER");

    if (!fullName) {
      jsonErr(400, "Full name is required.");
      return;
    }
    if (password.length < 8) {
      jsonErr(400, "Password must be at least 8 characters.");
      return;
    }
    if (!email && !username) {
      jsonErr(400, "Provide at least an email or a username.");
      return;
    }

    const roleMap: Record<string, UserRole> = {
      MANAGER: UserRole.MANAGER,
      STAFF: UserRole.STAFF,
      FRONTDESK: UserRole.FRONTDESK,
      FINANCE: UserRole.FINANCE,
      HOUSEKEEPING: UserRole.HOUSEKEEPING,
      RESTAURANT: "RESTAURANT" as UserRole
    };

    if (!Object.prototype.hasOwnProperty.call(roleMap, role)) {
      jsonErr(400, `Unknown role "${role}". Choose Manager, Staff, Front Desk, Finance, Housekeeping, or Restaurant.`);
      return;
    }
    const roleSafe = roleMap[role] ?? UserRole.MANAGER;
    const parsedPermissions = parsePermissionsFromBody(req.body as Record<string, unknown>);
    const permissions = permissionMatrixHasAny(parsedPermissions) ? parsedPermissions : defaultPermissionsForRole(roleSafe);
    const pinHash = pin.length >= 4 ? hashPassword(pin) : null;
    const passwordHash = hashPassword(password);

    // Do not set password-reset columns here: omit optional fields so INSERT stays minimal; DB columns come from migrate / startup repair.
    const createPayload = {
      hotelId: hotel.id,
      fullName,
      email,
      username,
      passwordHash,
      pinHash,
      role: roleSafe,
      isActive: true
    };

    /**
     * Two-phase create so a stale production Prisma client (which may not yet know
     * about a newly added UserRole enum value such as RESTAURANT) cannot block staff
     * onboarding. Phase 1 always upserts with `STAFF`, a role that has existed since
     * the very first migration. Phase 2 then writes the requested role via a
     * parameterized raw UPDATE — safe because SQLite stores Prisma enums as plain
     * TEXT and we already validated `role` against the explicit allow-list above.
     */
    const createPayloadBootstrap = { ...createPayload, role: UserRole.STAFF };
    try {
      if (email) {
        await prisma.hotelUser.upsert({
          where: { hotelId_email: { hotelId: hotel.id, email } },
          create: createPayloadBootstrap,
          update: {
            fullName,
            username,
            passwordHash,
            pinHash,
            role: UserRole.STAFF,
            isActive: true
          }
        });
      } else {
        await prisma.hotelUser.upsert({
          where: { hotelId_username: { hotelId: hotel.id, username: username! } },
          create: createPayloadBootstrap,
          update: {
            fullName,
            passwordHash,
            pinHash,
            role: UserRole.STAFF,
            isActive: true
          }
        });
      }
      // Phase 2: persist the requested role. Allow-list already enforced above; we
      // additionally pin the WHERE to (hotelId, email|username) so a typo cannot
      // touch a different tenant.
      if (email) {
        await prisma.$executeRaw`UPDATE "HotelUser" SET role = ${roleSafe} WHERE "hotelId" = ${hotel.id} AND email = ${email}`;
      } else {
        await prisma.$executeRaw`UPDATE "HotelUser" SET role = ${roleSafe} WHERE "hotelId" = ${hotel.id} AND username = ${username}`;
      }
    } catch (upsertErr) {
      console.error(
        "[admin] POST /users hotelUser.upsert failed:",
        { role: roleSafe, hasEmail: Boolean(email), hasUsername: Boolean(username) },
        upsertErr instanceof Error ? upsertErr.stack ?? upsertErr.message : String(upsertErr)
      );
      if (isHotelUserSchemaMismatchError(upsertErr)) {
        jsonErr(
          503,
          "Database schema is out of date. Run prisma migrate deploy on the server and restart the app."
        );
        return;
      }
      if (upsertErr instanceof Prisma.PrismaClientKnownRequestError && upsertErr.code === "P2002") {
        jsonErr(409, "A user with this email or username already exists for this hotel.");
        return;
      }
      if (upsertErr instanceof Prisma.PrismaClientValidationError) {
        jsonErr(
          500,
          `Could not create user: Prisma rejected the payload. Run prisma generate on the server and restart.`
        );
        return;
      }
      const detail =
        upsertErr instanceof Error && upsertErr.message
          ? upsertErr.message.slice(0, 240)
          : "Unknown database error";
      jsonErr(500, `Could not create user. ${detail}`);
      return;
    }

    try {
      const store = readPermissionStore();
      const permKey = email ? email.toLowerCase() : String(username).toLowerCase();
      store[permKey] = permissions;
      writePermissionStore(store);
    } catch (permErr) {
      console.error(
        "[admin] POST /users permission file write failed:",
        permErr instanceof Error ? permErr.message : String(permErr)
      );
      jsonErr(
        500,
        "User was created but permission settings could not be saved (server file write failed)."
      );
      return;
    }

    if (!res.headersSent) res.status(200).json({ success: true });
  } catch (err) {
    if (res.headersSent) {
      console.error("[admin] POST /users: response already sent", err);
      return;
    }
    if (isHotelUserSchemaMismatchError(err)) {
      console.error(
        "[admin] POST /users schema drift:",
        err instanceof Error ? err.message : String(err)
      );
      jsonErr(
        503,
        "Database schema is out of date. Run prisma migrate deploy on the server and restart the app."
      );
      return;
    }
    if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2002") {
      console.warn("[admin] POST /users duplicate key:", err.meta);
      jsonErr(409, "A user with this email or username already exists for this hotel.");
      return;
    }
    console.error("[admin] POST /users failed:", err instanceof Error ? err.message : String(err));
    jsonErr(500, "Could not create the user. Please try again.");
  }
});

adminRouter.post("/users/:id", requirePermission("USERS", "EDIT"), async (req, res) => {
  try {
    const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() }, select: { id: true } });
    if (!hotel) {
      res.redirect("/admin/users?error=hotel");
      return;
    }
    const userId = String(req.params.id ?? "");
    const existing = await prisma.hotelUser.findFirst({ where: { id: userId, hotelId: hotel.id } });
    if (!existing) {
      res.redirect("/admin/users?error=user");
      return;
    }

    const fullName = String(req.body.fullName ?? "").trim();
    const email = String(req.body.email ?? "").trim().toLowerCase() || null;
    const username = String(req.body.username ?? "").trim().toLowerCase() || null;
    const password = String(req.body.password ?? "");
    const pin = String(req.body.pin ?? "").trim();
    const roleRaw = String(req.body.role ?? String(existing.role));
    const isActive = req.body.isActive === "1" || req.body.isActive === "on";
    const roleMap: Record<string, UserRole> = {
      OWNER: UserRole.OWNER,
      MANAGER: UserRole.MANAGER,
      STAFF: UserRole.STAFF,
      FRONTDESK: UserRole.FRONTDESK,
      FINANCE: UserRole.FINANCE,
      HOUSEKEEPING: UserRole.HOUSEKEEPING,
      RESTAURANT: "RESTAURANT" as UserRole
    };
    const roleSafe = roleMap[roleRaw] ?? existing.role;

    if (!fullName || (!email && !username)) {
      res.redirect("/admin/users?error=missing");
      return;
    }
    if (password && password.length < 8) {
      res.redirect("/admin/users?error=password");
      return;
    }
    if (pin && pin.length < 4) {
      res.redirect("/admin/users?error=pin");
      return;
    }

    // Same two-phase write as POST /admin/users so a stale Prisma client cannot
    // refuse a freshly added enum value (e.g. RESTAURANT). The role allow-list
    // was already enforced via roleMap.
    const updateData: Prisma.HotelUserUpdateInput = {
      fullName,
      email,
      username,
      role: UserRole.STAFF,
      isActive
    };
    if (password) {
      updateData.passwordHash = hashPassword(password);
      updateData.passwordResetTokenHash = null;
      updateData.passwordResetExpiresAt = null;
      updateData.passwordResetRequestedAt = null;
    }
    if (pin) updateData.pinHash = hashPassword(pin);

    await prisma.hotelUser.update({ where: { id: existing.id }, data: updateData });
    await prisma.$executeRaw`UPDATE "HotelUser" SET role = ${roleSafe} WHERE id = ${existing.id}`;

    const permissions = parsePermissionsFromBody(req.body as Record<string, unknown>);
    const oldKey = hotelUserPermissionKey(existing);
    const newKey = hotelUserPermissionKey({ email, username });
    const store = readPermissionStore();
    if (oldKey && oldKey !== newKey) delete store[oldKey];
    if (newKey) store[newKey] = permissions;
    writePermissionStore(store);

    await logAudit({
      hotelId: hotel.id,
      action: "HOTEL_USER_UPDATED",
      entityType: "HotelUser",
      entityId: existing.id,
      metadata: {
        emailChanged: existing.email !== email,
        usernameChanged: existing.username !== username,
        role: String(roleSafe),
        isActive,
        passwordResetByManager: Boolean(password),
        pinResetByManager: Boolean(pin)
      }
    });
    res.redirect("/admin/users?updated=1");
  } catch (err) {
    if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2002") {
      res.redirect("/admin/users?error=duplicate");
      return;
    }
    console.error("[admin] POST /users/:id failed:", err instanceof Error ? err.message : String(err));
    res.redirect("/admin/users?error=update");
  }
});

adminRouter.post("/users/:id/send-reset", requirePermission("USERS", "EDIT"), async (req, res) => {
  const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() }, select: { id: true } });
  if (!hotel) {
    res.redirect("/admin/users?error=hotel");
    return;
  }
  const user = await prisma.hotelUser.findFirst({
    where: { id: String(req.params.id ?? ""), hotelId: hotel.id },
    select: { id: true, email: true, isActive: true }
  });
  if (!user?.email || !user.isActive) {
    res.redirect("/admin/users?error=reset");
    return;
  }
  await createPasswordResetForEmail(user.email, req);
  await logAudit({
    hotelId: hotel.id,
    action: "HOTEL_USER_PASSWORD_RESET_SENT_BY_MANAGER",
    entityType: "HotelUser",
    entityId: user.id,
    metadata: { email: user.email }
  });
  res.redirect("/admin/users?resetSent=1");
});

adminRouter.post("/users/:id/delete", requirePermission("USERS", "DELETE"), async (req, res) => {
  try {
    const hotel = await prisma.hotel.findUnique({ where: { slug: activeHotelSlug() }, select: { id: true } });
    if (!hotel) {
      res.redirect("/admin/users?error=hotel");
      return;
    }
    const target = await prisma.hotelUser.findFirst({
      where: { id: String(req.params.id ?? ""), hotelId: hotel.id },
      select: { id: true, email: true, username: true, role: true }
    });
    if (!target) {
      res.redirect("/admin/users?error=user");
      return;
    }
    const session = getSession(req);
    if (session?.staffId === target.id) {
      res.redirect("/admin/users?error=selfDelete");
      return;
    }

    const store = readPermissionStore();
    const permKey = hotelUserPermissionKey(target);

    try {
      await prisma.hotelUser.delete({ where: { id: target.id } });
      if (permKey) {
        delete store[permKey];
        writePermissionStore(store);
      }
      await logAudit({
        hotelId: hotel.id,
        action: "HOTEL_USER_DELETED",
        entityType: "HotelUser",
        entityId: target.id,
        metadata: { email: target.email, username: target.username, role: String(target.role) }
      });
      res.redirect("/admin/users?deleted=1");
    } catch (err) {
      if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2003") {
        await prisma.hotelUser.update({ where: { id: target.id }, data: { isActive: false } });
        await logAudit({
          hotelId: hotel.id,
          action: "HOTEL_USER_DEACTIVATED_INSTEAD_OF_DELETE",
          entityType: "HotelUser",
          entityId: target.id,
          metadata: { reason: "linked_operation_history", email: target.email, username: target.username, role: String(target.role) }
        });
        res.redirect("/admin/users?deactivated=1");
        return;
      }
      throw err;
    }
  } catch (err) {
    console.error("[admin] POST /users/:id/delete failed:", err instanceof Error ? err.message : String(err));
    res.redirect("/admin/users?error=delete");
  }
});

